import { Sun, Utensils, Footprints, Sparkles, Share2, Leaf, Heart, CheckCircle2, RotateCcw, Loader2, WheatOff, MilkOff, CandyOff, Clock, Info } from 'lucide-react';
import React, { useEffect, useState } from 'react';
import { generateDailyContent, generateSingleRecipe } from '../services/geminiService';
import { DailyContent, Recipe } from '../types';

const Guidance: React.FC = () => {
  const [content, setContent] = useState<DailyContent | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshingIds, setRefreshingIds] = useState<Set<number>>(new Set());

  useEffect(() => {
    const load = async () => {
        setLoading(true);
        const data = await generateDailyContent();
        setContent(data);
        setLoading(false);
    };
    load();
  }, []);

  const handleShare = async (recipe: Recipe) => {
    const shareText = `Confira esta receita nutritiva do ReViva: ${recipe.title}. Totalmente livre de glúten, leite e açúcar! ✨`;
    if (navigator.share) {
      try {
        await navigator.share({
          title: `ReViva - ${recipe.title}`,
          text: shareText,
          url: window.location.href,
        });
      } catch (err) {
        console.log('Erro ao compartilhar:', err);
      }
    } else {
      await navigator.clipboard.writeText(shareText);
      alert('Resumo da receita copiado! ✨');
    }
  };

  const handleRefreshRecipe = async (index: number, mealType: string) => {
    if (refreshingIds.has(index)) return;
    setRefreshingIds(prev => new Set(prev).add(index));
    try {
      const newRecipe = await generateSingleRecipe(mealType);
      setContent(prev => {
        if (!prev) return null;
        const newMenu = [...prev.menu];
        newMenu[index] = newRecipe;
        return { ...prev, menu: newMenu };
      });
    } catch (error) {
      console.error("Erro:", error);
    } finally {
      setRefreshingIds(prev => {
        const next = new Set(prev);
        next.delete(index);
        return next;
      });
    }
  };

  if (loading) {
    return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4">
            <div className="relative w-16 h-16">
              <div className="absolute inset-0 border-4 border-white/5 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-nature-500 rounded-full border-t-transparent animate-spin"></div>
            </div>
            <p className="text-ethereal-400 font-serif italic animate-pulse text-center px-8">Consultando os oráculos da nutrição para seu menu de 5 passos...</p>
        </div>
    );
  }

  return (
    <div className="p-6 pb-28 max-w-2xl mx-auto space-y-10 animate-in fade-in duration-1000">
       <header className="space-y-1">
          <h2 className="text-4xl font-serif text-white leading-tight">Guia da Essência</h2>
          <p className="text-nature-400 text-[10px] font-black uppercase tracking-widest">Alquimia em 5 Minutos</p>
       </header>

      {/* Mantra Card */}
      <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 relative overflow-hidden group">
        <Sun className="text-nature-400 absolute -top-4 -right-4 w-32 h-32 opacity-5 group-hover:scale-110 transition-transform duration-1000" />
        <div className="relative z-10 space-y-4">
          <div className="flex items-center gap-2 text-[10px] font-black text-nature-400 uppercase tracking-widest">
            <Sparkles size={14} /> Inspiração Diária
          </div>
          <p className="text-xl font-serif text-white leading-relaxed italic">
            "{content?.motivation}"
          </p>
        </div>
      </section>

      {/* Legenda de Restrições */}
      <section className="bg-nature-950/40 p-5 rounded-[2rem] border border-white/5 space-y-4">
        <div className="flex items-center gap-2 text-[10px] font-black text-ethereal-500 uppercase tracking-widest">
          <Info size={12} /> Legenda de Pureza Alimentar
        </div>
        <div className="flex flex-wrap gap-4">
          <div className="flex items-center gap-2">
            <div className="p-1.5 bg-nature-400/20 rounded-lg"><WheatOff size={14} className="text-nature-400" /></div>
            <span className="text-[10px] text-white font-bold uppercase tracking-widest">S/G: <span className="text-ethereal-500 font-medium">Sem Glúten</span></span>
          </div>
          <div className="flex items-center gap-2">
            <div className="p-1.5 bg-blue-400/20 rounded-lg"><MilkOff size={14} className="text-blue-400" /></div>
            <span className="text-[10px] text-white font-bold uppercase tracking-widest">S/L: <span className="text-ethereal-500 font-medium">Sem Leite</span></span>
          </div>
          <div className="flex items-center gap-2">
            <div className="p-1.5 bg-amber-400/20 rounded-lg"><CandyOff size={14} className="text-amber-400" /></div>
            <span className="text-[10px] text-white font-bold uppercase tracking-widest">S/A: <span className="text-ethereal-500 font-medium">Sem Açúcar</span></span>
          </div>
        </div>
      </section>

      {/* Challenge */}
      <section className="glass-mystic p-6 rounded-[2.5rem] border border-white/5 flex items-center gap-5">
         <div className="w-14 h-14 bg-white/5 rounded-2xl flex items-center justify-center shadow-sm shrink-0 text-nature-400 border border-white/10">
            <Footprints size={28} />
         </div>
         <div className="space-y-1">
            <h3 className="font-bold text-white text-sm">Ritual de Conexão</h3>
            <p className="text-ethereal-400 text-xs leading-relaxed">{content?.dailyChallenge}</p>
         </div>
      </section>

      {/* Recipes */}
      <section className="space-y-8">
        <div className="flex justify-between items-end px-2">
           <h3 className="text-2xl font-serif text-white flex items-center gap-3">
             <Utensils size={24} className="text-nature-400" /> Alquimia Nutritiva
           </h3>
           <span className="text-[9px] font-black text-magic-gold bg-magic-gold/10 px-3 py-1.5 rounded-full border border-magic-gold/20 uppercase tracking-widest">5 Refeições por Dia</span>
        </div>

        <div className="space-y-8">
          {content?.menu.map((recipe, index) => (
            <div key={index} className="relative glass-mystic rounded-[3rem] border border-white/5 overflow-hidden group hover:border-white/10 transition-all">

               {refreshingIds.has(index) && (
                 <div className="absolute inset-0 bg-nature-950/80 backdrop-blur-sm z-20 flex flex-col items-center justify-center animate-in fade-in">
                    <Loader2 className="text-nature-400 animate-spin mb-2" size={32} />
                 </div>
               )}

               <div className="p-8 space-y-6">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[10px] font-black text-nature-500 uppercase tracking-widest">{recipe.type}</span>
                        <div className="flex items-center gap-1 bg-white/5 px-2 py-0.5 rounded-md border border-white/5">
                           <Clock size={10} className="text-magic-gold" />
                           <span className="text-[8px] font-bold text-white uppercase">{recipe.prepTime || '5 min'}</span>
                        </div>
                      </div>
                      <h4 className="text-2xl font-serif text-white group-hover:text-nature-400 transition-colors leading-snug">{recipe.title}</h4>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => handleRefreshRecipe(index, recipe.type)} className="p-2.5 bg-white/5 text-ethereal-500 hover:text-white rounded-xl border border-white/5 transition-colors"><RotateCcw size={18} /></button>
                      <button onClick={() => handleShare(recipe)} className="p-2.5 bg-white/5 text-ethereal-500 hover:text-white rounded-xl border border-white/5 transition-colors"><Share2 size={18} /></button>
                    </div>
                  </div>

                  <div className="flex gap-3 flex-wrap">
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-nature-400/10 border border-nature-400/20 rounded-full">
                      <WheatOff size={12} className="text-nature-400" />
                      <span className="text-[10px] font-black text-nature-400 uppercase">Sem Glúten</span>
                    </div>
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-blue-400/10 border border-blue-400/20 rounded-full">
                      <MilkOff size={12} className="text-blue-400" />
                      <span className="text-[10px] font-black text-blue-400 uppercase">Sem Leite</span>
                    </div>
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-amber-400/10 border border-amber-400/20 rounded-full">
                      <CandyOff size={12} className="text-amber-400" />
                      <span className="text-[10px] font-black text-amber-400 uppercase">Sem Açúcar</span>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6 border-t border-white/5">
                    <div className="space-y-4">
                      <h5 className="text-[10px] font-black text-nature-400 uppercase tracking-widest flex items-center gap-2">
                        <Leaf size={14} /> Elementos
                      </h5>
                      <ul className="space-y-2">
                        {recipe.ingredients.map((ing, i) => (
                          <li key={i} className="text-xs text-ethereal-300 flex items-center gap-3">
                            <div className="w-1 h-1 bg-nature-500 rounded-full"></div>
                            {ing}
                          </li>
                        ))}
                      </ul>
                    </div>

                    <div className="space-y-4">
                      <h5 className="text-[10px] font-black text-nature-400 uppercase tracking-widest flex items-center gap-2">
                        <Sparkles size={14} /> Processo
                      </h5>
                      <div className="space-y-3">
                        {recipe.instructions.map((inst, i) => (
                          <p key={i} className="text-xs text-ethereal-400 leading-relaxed pl-4 border-l border-white/10">
                            {inst}
                          </p>
                        ))}
                      </div>
                    </div>
                  </div>
               </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

export default Guidance;

import React, { useEffect, useState, useMemo } from 'react';
import { UserProfile, DailyLog } from '../types';
import { CheckCircle2, Sparkles, Wind, Footprints, Leaf, Droplets, Scroll, Mountain, Heart, Star, CalendarDays, Lock, Circle, Target } from 'lucide-react';
import { analyzeUserLogs } from '../services/geminiService';

interface DashboardProps {
  userProfile: UserProfile;
  logs: DailyLog[];
  onToggleGoal: (goalKey: keyof DailyLog['completedActions']) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ userProfile, logs, onToggleGoal }) => {
  const [insight, setInsight] = useState<string | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const todayLog = logs.find(l => l.date === todayStr);

  const todaysGoals = [
    { id: 'diet', label: 'Nutrição Sagrada', completed: todayLog?.completedActions.diet, icon: Leaf, type: 'action' },
    { id: 'waterGoal', label: 'Água Cristalina', completed: todayLog?.completedActions.waterGoal, icon: Droplets, type: 'action' },
    { id: 'meditationOrBreathing', label: 'Respiração Cósmica', completed: todayLog?.completedActions.meditationOrBreathing, icon: Wind, type: 'action' },
    { id: 'exercise', label: 'Movimento Vital', completed: todayLog?.completedActions.exercise, icon: Footprints, type: 'action' },
    { id: 'earthing', label: 'Conexão Terra', completed: todayLog?.completedActions.earthing, icon: Mountain, type: 'action' },
    { id: 'emotionalWork', label: 'Cura da Essência', completed: todayLog?.completedActions.emotionalWork, icon: Heart, type: 'action' },
    { id: 'diary', label: 'Relato da Alma', completed: todayLog?.completedActions.diary, icon: Scroll, type: 'status' },
  ];

  const completedCount = todaysGoals.filter(g => g.completed).length;

  useEffect(() => {
    const fetchInsight = async () => {
      if (logs.length >= 2 && !insight) {
        setLoadingInsight(true);
        const result = await analyzeUserLogs(logs);
        setInsight(result);
        setLoadingInsight(false);
      }
    };
    fetchInsight();
  }, [logs]);

  return (
    <div className="p-6 pb-32 max-w-2xl mx-auto space-y-12 animate-in fade-in duration-1000 relative overflow-hidden">
      <div className="absolute top-20 right-0 w-64 h-64 bg-nature-400/5 blur-[120px] rounded-full pointer-events-none" />

      <header className="flex justify-between items-start relative z-10">
        <div className="space-y-1">
          <p className="text-nature-400 font-black text-[10px] uppercase tracking-[0.4em]">Portal de Presença</p>
          <h2 className="text-4xl font-serif text-white leading-tight">Olá, {userProfile.name}</h2>
        </div>
        <div className="glass-mystic text-white px-4 py-2 rounded-2xl flex items-center gap-2 border border-white/10">
          <Star size={14} className="text-nature-300" />
          <span className="text-[10px] font-bold uppercase tracking-widest">Dia {Math.floor((new Date().getTime() - new Date(userProfile.startDate!).getTime()) / (1000 * 3600 * 24)) + 1}</span>
        </div>
      </header>

      {/* Círculo de Luz de Progresso */}
      <section className="relative flex flex-col items-center justify-center py-8 glass-mystic rounded-[4rem] border border-white/5 shadow-inner bg-nature-950/20">
        <div className="relative w-40 h-40 flex items-center justify-center">
          <div className="absolute inset-0 bg-nature-500/10 blur-[40px] rounded-full animate-pulse"></div>
          <svg viewBox="0 0 100 100" className="w-full h-full transform -rotate-90">
            <circle cx="50" cy="50" r="45" fill="transparent" stroke="rgba(255,255,255,0.05)" strokeWidth="6" />
            <circle 
              cx="50" cy="50" r="45" 
              fill="transparent" 
              stroke="#7fa365" 
              strokeWidth="6" 
              strokeDasharray="283" 
              strokeDashoffset={283 - (283 * completedCount / 7)}
              strokeLinecap="round"
              className="transition-all duration-1000 ease-out"
            />
          </svg>
          <div className="absolute flex flex-col items-center">
            <span className="text-4xl font-serif font-bold text-white">{completedCount}</span>
            <span className="text-[8px] font-black text-nature-400 uppercase tracking-widest">Ativadas</span>
          </div>
        </div>
        <div className="mt-6 text-center space-y-1">
           <p className="text-[10px] font-black text-ethereal-500 uppercase tracking-[0.3em]">Alinhamento do Dia</p>
           <p className="text-[10px] text-nature-500 font-serif italic max-w-[200px] mx-auto opacity-70">Manifeste suas intenções para transformar seu hoje.</p>
        </div>
      </section>

      {/* INTENÇÕES SAGRADAS (PLANEJAMENTO) */}
      <section className="space-y-6">
        <div className="px-4 space-y-2">
          <div className="flex justify-between items-end">
            <h3 className="text-2xl font-serif text-white tracking-tight">Intenções Sagradas</h3>
            <Target size={18} className="text-nature-400 animate-pulse" />
          </div>
          <p className="text-[10px] text-ethereal-500 italic uppercase tracking-widest">Escolha agora como planeja honrar seu templo hoje</p>
        </div>

        {/* Banner de Instrução Curta */}
        <div className="mx-2 p-4 bg-white/5 rounded-3xl border border-white/10 flex items-center gap-4">
           <div className="p-2 bg-nature-400/20 rounded-full text-nature-400">
             <Sparkles size={16} />
           </div>
           <p className="text-[11px] text-ethereal-400 leading-relaxed">
             Marque as práticas que você <strong>planeja realizar</strong>. Este é o seu compromisso de luz para as próximas horas.
           </p>
        </div>

        <div className="grid grid-cols-1 gap-3 px-2">
          {todaysGoals.map((goal, idx) => {
            const GoalIcon = goal.icon;
            const isStatus = goal.type === 'status';

            return (
              <button 
                key={idx} 
                onClick={() => !isStatus && onToggleGoal(goal.id as any)}
                disabled={isStatus}
                className={`p-5 rounded-[2.5rem] flex items-center gap-5 border transition-all duration-300 text-left w-full active:scale-95 group ${
                  goal.completed 
                    ? 'bg-nature-900/40 border-nature-500/30' 
                    : 'glass-mystic border-white/5 hover:border-nature-400/20'
                } ${isStatus ? 'cursor-default opacity-80' : ''}`}
              >
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${
                  goal.completed ? 'bg-nature-500 text-nature-950 shadow-[0_0_15px_rgba(127,163,101,0.3)]' : 'bg-white/5 text-ethereal-600'
                }`}>
                  {goal.completed ? <CheckCircle2 size={24} /> : <GoalIcon size={24} />}
                </div>
                <div className="flex-1">
                  <span className={`font-bold text-sm tracking-tight block ${goal.completed ? 'text-nature-400' : 'text-white'}`}>
                    {goal.label}
                  </span>
                  {isStatus && !goal.completed ? (
                    <span className="text-[9px] text-ethereal-600 font-bold uppercase tracking-widest flex items-center gap-1 mt-0.5">
                      <Lock size={8} className="mb-0.5" /> Registre seu Diário ao fim do dia
                    </span>
                  ) : (
                    <span className="text-[9px] text-ethereal-600 font-medium uppercase tracking-widest mt-0.5">
                      {goal.completed ? 'Intenção Manifestada' : 'Firmar Intenção'}
                    </span>
                  )}
                </div>
                {!isStatus && !goal.completed && (
                   <Circle size={16} className="text-ethereal-800 group-hover:text-nature-400 transition-colors" />
                )}
              </button>
            );
          })}
        </div>
      </section>

      {/* Insight da Alma */}
      {insight && (
        <section className="px-4 animate-in slide-in-from-bottom-8">
           <div className="glass-mystic p-8 rounded-[3rem] border border-white/5 bg-nature-900/10 italic text-sm text-ethereal-300 leading-relaxed text-center relative">
              <Sparkles size={14} className="text-nature-400 absolute -top-2 left-1/2 -translate-x-1/2" />
              "{insight}"
           </div>
        </section>
      )}
    </div>
  );
};

export default Dashboard;

