import Tracker from './components/Tracker';
import Wellness from './components/Wellness';
import Guidance from './components/Guidance';
import Community from './components/Community';
import WelcomeCover from './components/WelcomeCover';
import { AppView, UserProfile, DailyLog } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.WELCOME);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Viajante',
    startDate: null,
    diagnosisScore: 0,
    hasSeenWarning: false,
    isOnDiet: false,
  });
  const [logs, setLogs] = useState<DailyLog[]>([]);

  useEffect(() => {
    const savedProfile = localStorage.getItem('userProfile');
    const savedLogs = localStorage.getItem('userLogs');

    if (savedProfile) {
      const parsedProfile = JSON.parse(savedProfile);
      setUserProfile(parsedProfile);
      if (parsedProfile.isOnDiet) {
        // Se já está na dieta, ainda mostramos a capa uma vez ou pulamos?
        // Vamos manter a capa como um ritual de entrada opcional se o usuário atualizar.
        // Para melhor UX, se já logado, vai direto pro Dashboard.
        setCurrentView(AppView.DASHBOARD);
      }
    }
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem('userProfile', JSON.stringify(userProfile));
  }, [userProfile]);

  useEffect(() => {
    localStorage.setItem('userLogs', JSON.stringify(logs));
  }, [logs]);

  const handleDiagnosisComplete = (score: number, name: string) => {
    setUserProfile(prev => ({
      ...prev,
      name: name,
      diagnosisScore: score,
      hasSeenWarning: true,
      startDate: new Date().toISOString(),
      isOnDiet: true
    }));
    setTimeout(() => setCurrentView(AppView.DASHBOARD), 1000);
  };

  const handleSaveLog = (log: DailyLog) => {
    setLogs(prev => {
      const exists = prev.findIndex(l => l.date === log.date);
      // Força o 'diary' como true ao salvar
      const updatedLog = { ...log, completedActions: { ...log.completedActions, diary: true } };

      if (exists >= 0) {
        const newLogs = [...prev];
        newLogs[exists] = updatedLog;
        return newLogs;
      }
      return [...prev, updatedLog];
    });
  };

  const toggleDailyGoal = (goalKey: keyof DailyLog['completedActions']) => {
    const today = new Date().toISOString().split('T')[0];
    setLogs(prev => {
      const existingIndex = prev.findIndex(l => l.date === today);
      const newLogs = [...prev];

      if (existingIndex >= 0) {
        const log = { ...newLogs[existingIndex] };
        log.completedActions = { 
          ...log.completedActions, 
          [goalKey]: !log.completedActions[goalKey] 
        };
        newLogs[existingIndex] = log;
      } else {
        const newLog: DailyLog = {
          date: today,
          meals: { breakfast: '', lunch: '', dinner: '', snacks: '' },
          symptomsPresent: [],
          mood: 3,
          waterIntake: 0,
          completedActions: {
            diet: false,
            diary: false,
            meditationOrBreathing: false,
            emotionalWork: false,
            exercise: false,
            earthing: false,
            waterGoal: false,
            [goalKey]: true
          }
        };
        newLogs.push(newLog);
      }
      return newLogs;
    });
  };

  const renderView = () => {
    switch (currentView) {
      case AppView.WELCOME:
        return <WelcomeCover onStart={() => setCurrentView(userProfile.isOnDiet ? AppView.DASHBOARD : AppView.DIAGNOSIS)} />;
      case AppView.DIAGNOSIS:
        return <Diagnosis onComplete={handleDiagnosisComplete} userProfile={userProfile} />;
      case AppView.DASHBOARD:
        return <Dashboard userProfile={userProfile} logs={logs} onToggleGoal={toggleDailyGoal} />;
      case AppView.TRACKER:
        return <Tracker onSaveLog={handleSaveLog} logs={logs} />;
      case AppView.WELLNESS:
        return <Wellness />;
      case AppView.GUIDANCE:
        return <Guidance />;
      case AppView.COMMUNITY:
        return <Community />;
      default:
        return <Dashboard userProfile={userProfile} logs={logs} onToggleGoal={toggleDailyGoal} />;
    }
  };

  return (
    <div className="min-h-screen bg-ethereal-950 text-gray-100 font-sans selection:bg-nature-400/30">
      <main className="mx-auto max-w-md bg-transparent min-h-screen shadow-2xl relative overflow-x-hidden">
        <div className="relative z-10">{renderView()}</div>
        <div className="fixed top-[-10%] left-[-10%] w-full h-full bg-nature-400/5 blur-[150px] pointer-events-none rounded-full" />
        <div className="fixed bottom-[-10%] right-[-10%] w-full h-full bg-ethereal-500/5 blur-[150px] pointer-events-none rounded-full" />
      </main>

      {userProfile.isOnDiet && currentView !== AppView.WELCOME && (
        <Navigation currentView={currentView} setView={setCurrentView} />
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { DailyLog, Recipe } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const modelId = "gemini-3-flash-preview"; 
const ttsModelId = "gemini-2.5-flash-preview-tts";
const imageModelId = "gemini-2.5-flash-image";

const SYSTEM_DIET_RULES = "As receitas devem ser OBRIGATORIAMENTE: Proteicas, ricas em gorduras boas (abacate, coco, sementes, nuts), Sem Glúten (S/G), Sem Leite/Lactose (S/L) e Sem Açúcar (S/A). Máximo 5 minutos de preparo.";

export const generateAppCover = async (): Promise<string | null> => {
  try {
    const response = await ai.models.generateContent({
      model: imageModelId,
      contents: {
        parts: [
          {
            text: "A breathtaking mystical and artistic cover for a wellness app called ReViva Agora. The theme is self-discovery, gut health, and emotional reconnection. Visual elements: lush deep green tropical leaves, golden mystical light particles, a radiant energy sphere representing the gut/center of being, midnight blue ethereal background, peaceful and spiritual atmosphere. Digital art style, professional, ultra-high resolution.",
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "9:16",
        },
      },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Erro ao gerar imagem de capa:", error);
    return null;
  }
};

export const generateDailyContent = async () => {
  try {
    const prompt = `Atue como um Guia Espiritual e Nutricionista Funcional. Crie um portal de sabedoria diário (JSON): menu (3 receitas principais: Desjejum, Almoço e Jantar), motivação e desafio diário. ${SYSTEM_DIET_RULES}`;
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            menu: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  title: { type: Type.STRING },
                  ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
                  instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
                  prepTime: { type: Type.STRING }
                }
              }
            },
            motivation: { type: Type.STRING },
            dailyChallenge: { type: Type.STRING }
          }
        }
      }
    });
    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    return null;
  }
};

