import { Sun, Utensils, Footprints, Sparkles, Share2, Leaf, Heart, CheckCircle2, RotateCcw, Loader2, WheatOff, MilkOff, Clock, Moon, Zap, ChevronRight, X, Timer, FlaskConical, ShieldCheck, Droplets, FlaskRound } from 'lucide-react';
import React, { useEffect, useState } from 'react';
import { generateDailyContent, generateRecipeOptions, generateFermentationRecipe, generatePurificationTips } from '../services/geminiService';
import { DailyContent, Recipe } from '../types';

const FASTING_WINDOWS = [12, 14, 16, 18, 24];

const Guidance: React.FC = () => {
  const [content, setContent] = useState<DailyContent | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshingIdx, setRefreshingIdx] = useState<number | null>(null);
  const [recipeOptions, setRecipeOptions] = useState<Recipe[]>([]);
  const [showOptionsModal, setShowOptionsModal] = useState(false);
  const [selectedMealIdx, setSelectedMealIdx] = useState<number | null>(null);

  const [fermentationRecipe, setFermentationRecipe] = useState<Recipe | null>(null);
  const [purificationTips, setPurificationTips] = useState<string[]>([]);
  const [loadingExtras, setLoadingExtras] = useState(false);

  // Jejum Intermitente
  const [fastingWindow, setFastingWindow] = useState<number>(16);
  const [isFasting, setIsFasting] = useState(false);

  useEffect(() => {
    const load = async () => {
        setLoading(true);
        const [data, ferment, tips] = await Promise.all([
          generateDailyContent(),
          generateFermentationRecipe(),
          generatePurificationTips()
        ]);
        setContent(data);
        setFermentationRecipe(ferment);
        setPurificationTips(tips);
        setLoading(false);
    };
    load();
  }, []);

  const handleRefreshFerment = async () => {
    setLoadingExtras(true);
    const ferment = await generateFermentationRecipe();
    setFermentationRecipe(ferment);
    setLoadingExtras(false);
  };

  const handleShare = async (recipe: Recipe) => {
    const shareText = `Confira esta receita nutritiva do ReViva: ${recipe.title}. S/G, S/L, S/A ✨`;
    if (navigator.share) {
      try {
        await navigator.share({ title: `ReViva - ${recipe.title}`, text: shareText, url: window.location.href });
      } catch (err) {}
    } else {
      await navigator.clipboard.writeText(shareText);
      alert('Copiado! ✨');
    }
  };

  const handleOpenRefresh = async (index: number, mealType: string) => {
    setRefreshingIdx(index);
    setSelectedMealIdx(index);
    const options = await generateRecipeOptions(mealType);
    setRecipeOptions(options);
    setShowOptionsModal(true);
    setRefreshingIdx(null);
  };

  const selectNewRecipe = (recipe: Recipe) => {
    if (selectedMealIdx === null || !content) return;
    const newMenu = [...content.menu];
    newMenu[selectedMealIdx] = recipe;
    setContent({ ...content, menu: newMenu });
    setShowOptionsModal(false);
    setRecipeOptions([]);
  };

  if (loading) {
    return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4">
            <div className="relative w-16 h-16">
              <div className="absolute inset-0 border-4 border-white/5 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-nature-500 rounded-full border-t-transparent animate-spin"></div>
            </div>
            <p className="text-ethereal-400 font-serif italic animate-pulse text-center px-8">Invocando a alquimia das 3 refeições sagradas...</p>
        </div>
    );
  }

  return (
    <div className="p-6 pb-28 max-w-2xl mx-auto space-y-10 animate-in fade-in duration-1000 relative">
       <header className="space-y-1">
          <h2 className="text-4xl font-serif text-white leading-tight">Guia da Essência</h2>
          <p className="text-nature-400 text-[10px] font-black uppercase tracking-widest">Alquimia, Pausa e Purificação</p>
       </header>

      {/* Mantra Card */}
      <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 relative overflow-hidden group">
        <Sun className="text-nature-400 absolute -top-4 -right-4 w-32 h-32 opacity-5 group-hover:scale-110 transition-transform duration-1000" />
        <div className="relative z-10 space-y-4">
          <div className="flex items-center gap-2 text-[10px] font-black text-nature-400 uppercase tracking-widest">
            <Sparkles size={14} /> Inspiração do Dia
          </div>
          <p className="text-lg font-serif text-white leading-relaxed italic">
            "{content?.motivation}"
          </p>
        </div>
      </section>

      {/* PURIFICAÇÃO DO TEMPLO (DESPARASITAÇÃO) */}
      <section className="glass-mystic p-8 rounded-[3rem] border border-nature-400/20 bg-nature-950/20 space-y-6">
         <div className="flex items-center gap-3">
            <div className="p-2 bg-nature-400/20 rounded-xl text-nature-400">
               <ShieldCheck size={20} />
            </div>
            <div>
               <h3 className="text-xl font-serif text-white">Purificação do Templo</h3>
               <p className="text-[10px] font-black text-nature-400 uppercase tracking-widest">Protocolo de Limpeza</p>
            </div>
         </div>
         <ul className="space-y-4">
            {purificationTips.map((tip, idx) => (
               <li key={idx} className="flex gap-4 items-start group">
                  <div className="mt-1 w-5 h-5 bg-nature-900 border border-white/10 rounded-full flex items-center justify-center text-[10px] font-bold text-nature-400 shrink-0 group-hover:bg-nature-400 group-hover:text-nature-900 transition-colors">
                     {idx + 1}
                  </div>
                  <p className="text-xs text-ethereal-300 leading-relaxed italic">
                    {tip}
                  </p>
               </li>
            ))}
         </ul>
         <p className="text-[9px] text-ethereal-600 uppercase tracking-widest text-center mt-4">Safe & Natural • Sem Contraindicações</p>
      </section>

      {/* SEÇÃO DE JEJUM INTERMITENTE */}
      <section className="glass-mystic p-8 rounded-[3rem] border border-magic-gold/20 bg-gradient-to-br from-nature-950/40 to-ethereal-950/40 space-y-6">
         <div className="flex justify-between items-center">
            <div className="flex items-center gap-3">
               <div className="p-2 bg-magic-gold/20 rounded-xl text-magic-gold">
                  <Moon size={20} />
               </div>
               <div>
                  <h3 className="text-xl font-serif text-white">Pausa Sagrada</h3>
                  <p className="text-[10px] font-black text-magic-gold uppercase tracking-widest">Jejum Intermitente</p>
               </div>
            </div>
            <div className={`p-2 rounded-full transition-all ${isFasting ? 'bg-magic-gold text-nature-950' : 'bg-white/5 text-ethereal-500'}`}>
               <Timer size={18} />
            </div>
         </div>

         <p className="text-xs text-ethereal-400 italic">
           Honre o silêncio digestivo para permitir que sua essência se regenere. Escolha seu portal de tempo:
         </p>

         <div className="flex flex-wrap gap-2">
            {FASTING_WINDOWS.map(hours => (
               <button
                  key={hours}
                  onClick={() => setFastingWindow(hours)}
                  className={`px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border ${
                     fastingWindow === hours ? 'bg-magic-gold text-nature-950 border-magic-gold' : 'glass-mystic text-ethereal-500 border-white/5'
                  }`}
               >
                  {hours}h
               </button>
            ))}
         </div>

         <button 
            onClick={() => setIsFasting(!isFasting)}
            className={`w-full py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-2 ${
               isFasting ? 'bg-red-950/50 text-red-400 border border-red-900' : 'bg-white text-nature-950 shadow-xl'
            }`}
         >
            {isFasting ? <><X size={16} /> Encerrar Protocolo</> : <><Zap size={16} /> Iniciar Janela de {fastingWindow}h</>}
         </button>
      </section>

      {/* ALQUIMIA DE FERMENTADOS */}
      {fermentationRecipe && (
        <section className="space-y-6">
           <div className="flex justify-between items-end px-2">
              <h3 className="text-2xl font-serif text-white flex items-center gap-3">
                <FlaskConical size={24} className="text-magic-gold" /> Alquimia Viva
              </h3>
              <button 
                onClick={handleRefreshFerment}
                className="p-2 bg-white/5 rounded-xl border border-white/10 text-ethereal-500 hover:text-white transition-all disabled:opacity-50"
                disabled={loadingExtras}
              >
                {loadingExtras ? <Loader2 size={16} className="animate-spin" /> : <RotateCcw size={16} />}
              </button>
           </div>

           <div className="glass-mystic p-8 rounded-[3rem] border border-magic-gold/10 relative overflow-hidden group">
              <div className="absolute -bottom-10 -right-10 w-40 h-40 bg-magic-gold/5 rounded-full blur-[60px]" />
              <div className="space-y-4">
                 <div className="flex items-center gap-2">
                    <span className="text-[10px] font-black text-magic-gold uppercase tracking-widest">Fermentação Probiótica</span>
                    <div className="bg-magic-gold/10 px-2 py-0.5 rounded-md text-[8px] font-bold text-magic-gold uppercase">Saúde Intestinal</div>
                 </div>
                 <h4 className="text-2xl font-serif text-white">{fermentationRecipe.title}</h4>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4">
                    <div className="space-y-3">
                       <h5 className="text-[10px] font-black text-ethereal-500 uppercase tracking-widest flex items-center gap-2"><Droplets size={12} /> Base</h5>
                       <ul className="space-y-1">
                          {fermentationRecipe.ingredients.map((ing, i) => (
                             <li key={i} className="text-xs text-ethereal-300">• {ing}</li>
                          ))}
                       </ul>
                    </div>
                    <div className="space-y-2">
                       <h5 className="text-[10px] font-black text-ethereal-500 uppercase tracking-widest flex items-center gap-2"><Clock size={12} /> Transformação</h5>
                       <p className="text-[11px] text-ethereal-400 italic leading-relaxed">
                          {fermentationRecipe.instructions[0]}...
                       </p>
                    </div>
                 </div>
              </div>
           </div>
        </section>
      )}

      {/* Recipes Tríade */}
      <section className="space-y-8">
        <div className="flex justify-between items-end px-2">
           <h3 className="text-2xl font-serif text-white flex items-center gap-3">
             <Utensils size={24} className="text-nature-400" /> Tríade Sagrada
           </h3>
           <span className="text-[9px] font-black text-nature-400 bg-nature-400/10 px-3 py-1.5 rounded-full border border-nature-400/20 uppercase tracking-widest">3 Refeições</span>
        </div>

        <div className="space-y-8">
          {content?.menu.map((recipe, index) => (
