               const isPapaya = tip.toLowerCase().includes('mamão') || tip.toLowerCase().includes('sementes');
               return (
                  <li key={idx} className={`flex gap-4 items-start group p-3 rounded-2xl transition-all ${isPapaya ? 'bg-nature-400/5 border border-nature-400/10' : ''}`}>
                     <div className="mt-1 w-5 h-5 bg-nature-900 border border-white/10 rounded-full flex items-center justify-center text-[10px] font-bold text-nature-400 shrink-0">
                        {idx + 1}
                     </div>
                     <div className="space-y-1">
                        <p className="text-xs text-ethereal-300 leading-relaxed italic">
                          {tip}
                        </p>
                        {isPapaya && (
                           <span className="flex items-center gap-1.5 text-[9px] font-black text-magic-gold uppercase tracking-widest">
                              <AlertCircle size={10} /> Passo Essencial: Precisa Mastigar
                           </span>
                        )}
                     </div>
                  </li>
               );
            })}
         </ul>
      </section>

      {/* JEJUM INTERMITENTE */}
      <section className="glass-mystic p-8 rounded-[3rem] border border-magic-gold/20 space-y-6">
         <div className="flex justify-between items-center">
            <div className="flex items-center gap-3">
               <div className="p-2 bg-magic-gold/20 rounded-xl text-magic-gold">
                  <Moon size={20} />
               </div>
               <div>
                  <h3 className="text-xl font-serif text-white">Pausa Sagrada</h3>
                  <p className="text-[10px] font-black text-magic-gold uppercase tracking-widest">Jejum Diário</p>
               </div>
            </div>
            <div className={`p-2 rounded-full transition-all ${isFasting ? 'bg-magic-gold text-nature-950' : 'bg-white/5 text-ethereal-500'}`}>
               <Timer size={18} />
            </div>
         </div>

         <div className="flex flex-wrap gap-2">
            {FASTING_WINDOWS.map(hours => (
               <button
                  key={hours}
                  onClick={() => setFastingWindow(hours)}
                  className={`px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border ${
                     fastingWindow === hours ? 'bg-magic-gold text-nature-950 border-magic-gold' : 'glass-mystic text-ethereal-500 border-white/5'
                  }`}
               >
                  {hours}h
               </button>
            ))}
         </div>

         <button 
            onClick={() => setIsFasting(!isFasting)}
            className={`w-full py-4 rounded-2xl font-bold text-xs uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-2 ${
               isFasting ? 'bg-red-950/50 text-red-400 border border-red-900' : 'bg-white text-nature-950'
            }`}
         >
            {isFasting ? <><X size={16} /> Encerrar Protocolo</> : <><Zap size={16} /> Iniciar Janela</>}
         </button>
      </section>

      {/* FERMENTADOS */}
      {fermentationRecipe && (
        <section className="space-y-6">
           <div className="flex justify-between items-end px-2">
              <h3 className="text-2xl font-serif text-white flex items-center gap-3">
                <FlaskConical size={24} className="text-magic-gold" /> Alquimia Viva
              </h3>
              <button 
                onClick={handleRefreshFerment}
                className="p-2 bg-white/5 rounded-xl border border-white/10 text-ethereal-500"
                disabled={loadingExtras}
              >
                {loadingExtras ? <Loader2 size={16} className="animate-spin" /> : <RotateCcw size={16} />}
              </button>
           </div>
           <div className="glass-mystic p-8 rounded-[3rem] border border-magic-gold/10">
              <h4 className="text-xl font-serif text-white mb-4">{fermentationRecipe.title}</h4>
              <ul className="space-y-2 mb-4">
                 {fermentationRecipe.ingredients.map((ing, i) => (
                    <li key={i} className="text-xs text-ethereal-400">• {ing}</li>
                 ))}
              </ul>
              <p className="text-xs text-ethereal-500 italic">{fermentationRecipe.instructions[0]}</p>
           </div>
        </section>
      )}

      {/* REFEIÇÕES */}
      <section className="space-y-8">
        <h3 className="text-2xl font-serif text-white px-2">Tríade Sagrada</h3>
        {content?.menu.map((recipe, index) => (
          <div key={index} className="relative glass-mystic rounded-[3rem] border border-white/5 p-8 space-y-6">
            <div className="flex justify-between items-start">
              <div>
                <span className="text-[10px] font-black text-nature-500 uppercase tracking-widest">{recipe.type}</span>
                <h4 className="text-2xl font-serif text-white leading-snug">{recipe.title}</h4>
              </div>
              <button onClick={() => handleOpenRefresh(index, recipe.type)} className="p-3 bg-white/5 text-ethereal-500 rounded-2xl border border-white/5">
                <RotateCcw size={18} />
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <h5 className="text-[10px] font-black text-nature-400 uppercase tracking-widest">Elementos</h5>
                {recipe.ingredients.map((ing, i) => <p key={i} className="text-xs text-ethereal-300">• {ing}</p>)}
              </div>
              <div className="space-y-2">
                <h5 className="text-[10px] font-black text-nature-400 uppercase tracking-widest">Processo</h5>
                <p className="text-xs text-ethereal-400 leading-relaxed italic">{recipe.instructions[0]}</p>
              </div>
            </div>
          </div>
        ))}
      </section>

      {/* MODAL OPÇÕES */}
      {showOptionsModal && (
        <div className="fixed inset-0 z-[100] bg-ethereal-950/90 backdrop-blur-xl flex items-center justify-center p-4">
           <div className="bg-nature-950 border border-white/10 w-full max-w-lg rounded-[3rem] p-8 space-y-6 overflow-y-auto max-h-[80vh]">
              <div className="flex justify-between items-center">
                <h4 className="text-2xl font-serif text-white">Alternativas</h4>
                <button onClick={() => setShowOptionsModal(false)} className="text-ethereal-500"><X size={24} /></button>
              </div>
              <div className="space-y-4">
                 {recipeOptions.map((opt, i) => (
                    <button key={i} onClick={() => selectNewRecipe(opt)} className="w-full p-6 glass-mystic border border-white/5 rounded-[2rem] text-left hover:border-nature-400 transition-all">
                       <h5 className="text-white font-serif">{opt.title}</h5>
                       <p className="text-[10px] text-ethereal-500 uppercase mt-1">Clique para selecionar</p>
                    </button>
                 ))}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

