import React, { useState, useEffect, useMemo } from 'react';
import { Save, Plus, Minus, Droplets, History, Edit3, CalendarDays, Coffee, Sun, Sunset, Moon, Scroll, Quote, Activity, Sparkles, Wind, Leaf, Heart, BookOpen, Map, ChevronRight, Compass, Feather, Target, Wand2 } from 'lucide-react';
import { DailyLog, Symptom } from '../types';

const SYMPTOMS: Symptom[] = [
  { id: '1', name: 'Inchaço abdominal', category: 'digestivo', weight: 3 },
  { id: '4', name: 'Brain Fog', category: 'neurologico', weight: 3 },
  { id: '5', name: 'Dor de cabeça', category: 'neurologico', weight: 2 },
  { id: '11', name: 'Tontura', category: 'neurologico', weight: 2 },
  { id: '6', name: 'Cansaço', category: 'outro', weight: 2 },
  { id: '9', name: 'Ansiedade', category: 'emocional', weight: 1 },
  { id: 'other', name: 'Outros (descreva na reflexão)', category: 'outro', weight: 1 },
];

interface TrackerProps {
  onSaveLog: (log: DailyLog) => void;
  logs: DailyLog[];
}

const Tracker: React.FC<TrackerProps> = ({ onSaveLog, logs }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [meals, setMeals] = useState({ breakfast: '', lunch: '', dinner: '', snacks: '' });
  const [reflection, setReflection] = useState('');
  const [symptoms, setSymptoms] = useState<string[]>([]);
  const [mood, setMood] = useState(3);
  const [waterGlasses, setWaterGlasses] = useState(0);

  const [habits, setHabits] = useState({
    diet: false,
    meditation: false,
    exercise: false,
    earthing: false,
    emotionalWork: false
  });

  const sortedLogs = useMemo(() => {
    return [...logs].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [logs]);

  // Sugestão de prompt baseada em sintomas
  const soulPrompt = useMemo(() => {
    if (symptoms.length === 0) return null;
    const selectedNames = SYMPTOMS
      .filter(s => symptoms.includes(s.id))
      .map(s => s.name.toLowerCase())
      .join(', ');
    return `Sua alma sente hoje ${selectedNames}. Como você honra isso em sua jornada?`;
  }, [symptoms]);

  useEffect(() => {
    const existingLog = logs.find(l => l.date === date);
    if (existingLog) {
      setMeals(existingLog.meals);
      setReflection(existingLog.reflection || '');
      setSymptoms(existingLog.symptomsPresent || []);
      setMood(existingLog.mood);
      setWaterGlasses(existingLog.waterIntake || 0);
      setHabits({
        diet: existingLog.completedActions.diet,
        meditation: existingLog.completedActions.meditationOrBreathing,
        exercise: existingLog.completedActions.exercise,
        earthing: existingLog.completedActions.earthing,
        emotionalWork: existingLog.completedActions.emotionalWork
      });
    } else {
      setMeals({ breakfast: '', lunch: '', dinner: '', snacks: '' });
      setReflection('');
      setSymptoms([]);
      setMood(3);
      setWaterGlasses(0);
      setHabits({ diet: false, meditation: false, exercise: false, earthing: false, emotionalWork: false });
    }
  }, [date, logs]);

  const handleSave = () => {
    onSaveLog({
      date,
      meals,
      reflection,
      symptomsPresent: symptoms,
      mood,
      waterIntake: waterGlasses,
      completedActions: { 
        ...habits,
        diet: habits.diet,
        diary: reflection.length > 5, 
        meditationOrBreathing: habits.meditation,
        waterGoal: waterGlasses >= 8 
      }
    });
    alert(`Jornada atualizada e Alma ouvida! ✨`);
  };

  const handleEditPastLog = (pastDate: string) => {
    setDate(pastDate);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const toggleSymptom = (id: string) => {
    setSymptoms(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const applySoulPrompt = () => {
    if (soulPrompt) {
      setReflection(prev => prev ? `${prev}\n\n${soulPrompt}` : soulPrompt);
    }
  };

  const mealConfigs = [
    { id: 'breakfast', label: 'Despertar Proteico', icon: Coffee, placeholder: 'O que nutriu seu corpo ao acordar?' },
    { id: 'lunch', label: 'Almoço Funcional', icon: Sun, placeholder: 'Descreva sua refeição principal...' },
    { id: 'dinner', label: 'Ceia Leve', icon: Sunset, placeholder: 'Último alimento do dia (idealmente até às 20h)...' },
    { id: 'snacks', label: 'Lanches de Consciência', icon: Moon, placeholder: 'Nuts, sementes ou frutas?' },
  ];

  const journeyHabits = [
    { id: 'diet', label: 'Nutrição Limpa (S/G, S/L, S/A)', icon: Leaf },
    { id: 'meditation', label: 'Meditação ou Respiração', icon: Wind },
    { id: 'exercise', label: 'Movimento Físico', icon: Target },
    { id: 'earthing', label: 'Conexão com a Natureza', icon: Map },
    { id: 'emotionalWork', label: 'Prática de Cura Emocional', icon: Heart },
  ];

  return (
    <div className="p-4 pb-40 max-w-2xl mx-auto space-y-12 animate-in fade-in duration-500">
      <header className="px-4">
        <h2 className="text-4xl font-serif text-white tracking-tight">Recordatário</h2>
        <p className="text-nature-400 text-[10px] font-black uppercase tracking-[0.4em]">Diário e Histórico de Cura</p>
      </header>

      {/* Seletor de Data */}
      <div className="glass-mystic p-6 rounded-[3rem] border border-white/10 mx-2 flex justify-between items-center shadow-xl">
        <div className="flex items-center gap-4">
          <CalendarDays className="text-nature-400" size={20} />
          <div>
            <span className="text-[10px] font-black uppercase text-ethereal-600 block">Registro do dia:</span>
            <span className="text-white font-serif text-lg">{new Date(date + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}</span>
          </div>
        </div>
        <div className="relative">
          <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="absolute inset-0 opacity-0 cursor-pointer" />
          <div className="p-3 bg-white/5 rounded-2xl border border-white/10 text-white"><Edit3 size={18} /></div>
        </div>
      </div>

      <div className="space-y-10">

        {/* PARTE 1: REFLEXÃO DA ALMA (SUBJETIVO) */}
        <div className="space-y-4 px-2">
           <div className="flex items-center gap-2">
             <Feather size={16} className="text-nature-400" />
             <span className="text-[10px] font-black text-ethereal-500 uppercase tracking-widest">A Alma: Insights e Sentimentos</span>
           </div>

           <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-6 bg-nature-950/20 relative">
              <h3 className="font-serif text-2xl text-white flex items-center gap-3">
                <div className="w-1.5 h-6 bg-magic-gold rounded-full"></div> Reflexão da Alma
              </h3>

              {soulPrompt && (
                <button 
                  onClick={applySoulPrompt}
                  className="w-full p-4 rounded-2xl bg-magic-gold/10 border border-magic-gold/20 text-left group hover:bg-magic-gold/20 transition-all animate-in slide-in-from-top-2"
                >
                  <div className="flex items-center gap-2 mb-1">
                    <Wand2 size={12} className="text-magic-gold" />
                    <span className="text-[9px] font-black text-magic-gold uppercase tracking-widest">Sugestão da Alma</span>
                  </div>
                  <p className="text-[11px] text-magic-gold italic leading-relaxed">
                    "{soulPrompt}"
                  </p>
                  <span className="text-[8px] font-bold text-ethereal-600 uppercase mt-2 block group-hover:text-magic-gold transition-colors">Clique para incorporar ao seu relato</span>
                </button>
              )}

              <p className="text-xs text-ethereal-500 italic leading-relaxed">
                Um espaço livre. Não foque em tarefas aqui. **O que você sentiu hoje?** Qual insight ou gratidão brotou do seu coração?
              </p>
              <textarea 
                className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-6 text-sm text-white focus:border-magic-gold/50 outline-none resize-none placeholder:text-ethereal-800 italic leading-relaxed"
                placeholder="Hoje minha alma percebeu que..."
                rows={5}
                value={reflection}
                onChange={(e) => setReflection(e.target.value)}
              />
           </section>
        </div>

        {/* PARTE 2: OBJETIVOS DA JORNADA (CONCRETO) */}
        <div className="space-y-4 px-2">
           <div className="flex items-center gap-2">
             <Compass size={16} className="text-nature-400" />
             <span className="text-[10px] font-black text-ethereal-500 uppercase tracking-widest">A Jornada: Passos Concretos</span>
           </div>

           <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-6">
              <h3 className="font-serif text-2xl text-white flex items-center gap-3">
                <div className="w-1.5 h-6 bg-nature-400 rounded-full"></div> Objetivos Diários
              </h3>
              <p className="text-xs text-ethereal-500 italic leading-relaxed">
                Estes são os seus **degraus práticos**. Marque o que você efetivamente realizou para ancorar sua cura no plano físico.
              </p>

              <div className="space-y-3">
                {journeyHabits.map(habit => (
                  <button
                    key={habit.id}
                    onClick={() => setHabits(prev => ({ ...prev, [habit.id]: !prev[habit.id as keyof typeof habits] }))}
                    className={`w-full p-4 rounded-2xl border transition-all flex items-center gap-4 text-left ${
                      habits[habit.id as keyof typeof habits] 
                        ? 'bg-nature-900/40 border-nature-400/50 text-white' 
                        : 'bg-white/5 border-white/5 text-ethereal-600'
                    }`}
                  >
                    <div className={`p-2 rounded-lg ${habits[habit.id as keyof typeof habits] ? 'bg-nature-500 text-nature-950' : 'bg-white/5'}`}>
                      <habit.icon size={16} />
                    </div>
                    <span className="text-xs font-bold uppercase tracking-widest flex-1">{habit.label}</span>
                    {habits[habit.id as keyof typeof habits] && <Activity size={14} className="text-nature-400" />}
                  </button>
                ))}
              </div>
           </section>
        </div>

        {/* ALQUIMIA ALIMENTAR */}
        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-8">
           <h3 className="font-serif text-2xl text-white flex items-center gap-3">
             <div className="w-1.5 h-6 bg-nature-400 rounded-full"></div> Relato Nutritivo
          </h3>
          <div className="space-y-8">
            {mealConfigs.map(config => (
              <div key={config.id} className="space-y-3">
                <div className="flex items-center gap-2 px-2">
                  <config.icon size={16} className="text-nature-400" />
                  <label className="text-sm font-serif text-white">{config.label}</label>
                </div>
                <textarea 
                  className="w-full bg-white/5 border border-white/5 rounded-3xl p-5 text-sm text-white focus:border-nature-400/30 outline-none resize-none placeholder:text-ethereal-800"
                  placeholder={config.placeholder}
                  rows={2}
                  value={meals[config.id as keyof typeof meals]}
                  onChange={(e) => setMeals({...meals, [config.id]: e.target.value})}
                />
              </div>
            ))}
          </div>
        </section>

        {/* SINTOMAS */}
        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-6">
          <h3 className="font-serif text-2xl text-white flex items-center gap-3">
             <div className="w-1.5 h-6 bg-rose-500 rounded-full"></div> Sinais do Templo
          </h3>
          <div className="grid grid-cols-2 gap-2">
            {SYMPTOMS.map(s => (
              <button
                key={s.id}
                onClick={() => toggleSymptom(s.id)}
                className={`p-4 rounded-2xl text-[11px] font-bold border transition-all text-left flex justify-between items-center ${symptoms.includes(s.id) ? 'bg-rose-950/30 border-rose-500/50 text-rose-200' : 'bg-white/5 border-transparent text-ethereal-600'}`}
              >
                {s.name}
              </button>
            ))}
          </div>
        </section>

        {/* ÁGUA E HUMOR */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-4">
           <div className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-4">
              <span className="text-[10px] font-black uppercase text-blue-400 tracking-widest flex items-center gap-2"><Droplets size={12}/> Hidratação</span>
              <div className="flex items-center justify-between bg-white/5 p-4 rounded-2xl">
                 <button onClick={() => setWaterGlasses(Math.max(0, waterGlasses - 1))} className="text-blue-400"><Minus size={18}/></button>
                 <span className="text-white font-bold">{waterGlasses * 250}ml</span>
                 <button onClick={() => setWaterGlasses(waterGlasses + 1)} className="text-blue-400"><Plus size={18}/></button>
              </div>
           </div>
           <div className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-4 text-center">
              <span className="text-[10px] font-black uppercase text-nature-400 tracking-widest">Vibração Vital</span>
              <div className="flex justify-center gap-2">
                {[1,2,3,4,5].map(v => (
                  <button key={v} onClick={() => setMood(v)} className={`w-10 h-10 rounded-xl font-bold transition-all ${mood === v ? 'bg-white text-nature-950' : 'bg-white/5 text-ethereal-700'}`}>{v}</button>
                ))}
              </div>
           </div>
        </section>

        <button 
           onClick={handleSave}
           className="w-full bg-nature-500 text-white py-6 rounded-[3rem] font-bold text-lg flex items-center justify-center gap-4 shadow-2xl active:scale-95 transition-transform"
        >
           <Save size={24} /> Eternizar Relato do Dia
        </button>

        {/* HISTÓRICO: A MINHA JORNADA */}
        <section className="space-y-8 pt-12">
          <div className="flex flex-col gap-2 px-6">
            <div className="flex items-center gap-2">
               <Map size={16} className="text-nature-400" />
               <span className="text-[10px] font-black text-ethereal-500 uppercase tracking-widest">Mapa de Evolução</span>
            </div>
            <h3 className="text-3xl font-serif text-white">Minha Jornada</h3>
            <p className="text-xs text-nature-500 italic">Visualize os passos concretos que você deu em sua trilha de cura.</p>
          </div>

          <div className="relative px-4 space-y-6">
            <div className="absolute left-10 top-0 bottom-0 w-px bg-gradient-to-b from-nature-400/20 via-white/5 to-transparent ml-[-0.5px]" />

            {sortedLogs.length === 0 ? (
              <div className="p-12 text-center glass-mystic rounded-[2rem] border border-white/5 border-dashed">
                <p className="text-ethereal-600 italic text-sm">A jornada começa com o primeiro passo.</p>
              </div>
            ) : (
              sortedLogs.map((log) => {
                const completedSteps = Object.values(log.completedActions).filter(Boolean).length;
                return (
                  <div key={log.date} className="relative pl-12">
                    <div className={`absolute left-0 top-6 w-5 h-5 rounded-full border-4 shadow-lg z-10 ${log.date === date ? 'bg-white border-nature-400' : 'bg-nature-950 border-white/10'}`} />

                    <div className={`p-6 rounded-[2.5rem] border transition-all ${log.date === date ? 'bg-nature-900 border-nature-500' : 'glass-mystic border-white/5'}`}>
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <span className="text-[10px] font-black uppercase text-nature-500">{new Date(log.date + 'T00:00:00').toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
                          <h4 className="text-white font-serif text-lg">{new Date(log.date + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' })}</h4>
                        </div>
                        <div className="text-right">
                          <span className="text-[10px] font-black text-nature-400 uppercase tracking-widest block">Passos Concretos</span>
                          <span className="text-xs font-bold text-white">{completedSteps} / 7</span>
                        </div>
                      </div>

                      {/* Progresso Visual na Jornada */}
                      <div className="w-full h-1.5 bg-white/5 rounded-full mb-4 overflow-hidden">
                        <div 
                          className="h-full bg-nature-400 transition-all duration-1000" 
                          style={{ width: `${(completedSteps / 7) * 100}%` }}
                        />
                      </div>

                      {log.reflection && (
                        <div className="p-4 bg-white/5 rounded-2xl border-l-2 border-magic-gold/30">
                          <p className="text-xs text-ethereal-300 italic line-clamp-2 italic leading-relaxed">
                            "{log.reflection}"
                          </p>
                        </div>
                      )}

                      <button 
                        onClick={() => handleEditPastLog(log.date)} 
                        className="mt-4 flex items-center gap-2 text-[10px] font-bold text-ethereal-400 hover:text-white transition-all"
                      >
                        Revisitar Dia <ChevronRight size={10} />
                      </button>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

