          <div className="glass-mystic text-white px-4 py-2 rounded-2xl flex items-center gap-2 border border-white/10">
            <Star size={14} className="text-nature-300" />
            <span className="text-[10px] font-bold uppercase tracking-widest">Dia {Math.floor((new Date().getTime() - new Date(userProfile.startDate!).getTime()) / (1000 * 3600 * 24)) + 1}</span>
          </div>
        </div>
      </header>

      {/* CHAMADO MATINAL (BANNER DE LEMBRETE) */}
      {!hasStartedDay && (
        <section className="animate-in slide-in-from-top-4 duration-1000">
           <div className="relative p-8 rounded-[3rem] overflow-hidden border border-magic-gold/20 shadow-[0_20px_50px_rgba(212,175,55,0.1)] bg-gradient-to-br from-nature-950/80 to-ethereal-950/80 backdrop-blur-xl group">
              <div className="absolute -top-10 -right-10 w-40 h-40 bg-magic-gold/10 rounded-full blur-[40px] group-hover:bg-magic-gold/20 transition-all" />
              <div className="relative z-10 flex flex-col gap-4">
                 <div className="flex items-center gap-3">
                    <div className="p-3 bg-magic-gold/20 rounded-2xl text-magic-gold">
                       <Sunrise size={24} className="animate-pulse" />
                    </div>
                    <div>
                       <h3 className="text-xl font-serif text-white leading-tight">Ritual de Despertar</h3>
                       <p className="text-[10px] font-black text-magic-gold uppercase tracking-widest">Ação Necessária</p>
                    </div>
                 </div>
                 <p className="text-sm text-ethereal-300 italic leading-relaxed">
                   O sol despertou sua essência. Seu altar de intenções está aguardando seu toque para guiar o fluxo deste novo dia.
                 </p>
                 <button 
                   onClick={() => document.getElementById('intentions-section')?.scrollIntoView({ behavior: 'smooth' })}
                   className="w-fit flex items-center gap-2 px-6 py-3 bg-magic-gold text-nature-950 rounded-2xl font-bold text-xs uppercase tracking-widest hover:scale-105 transition-transform active:scale-95"
                 >
                   Firmar Intenções <Zap size={14} />
                 </button>
              </div>
           </div>
        </section>
      )}

      {/* Círculo de Luz de Progresso */}
      <section className="relative flex flex-col items-center justify-center py-8 glass-mystic rounded-[4rem] border border-white/5 shadow-inner bg-nature-950/20">
        <div className="relative w-40 h-40 flex items-center justify-center">
          <div className="absolute inset-0 bg-nature-500/10 blur-[40px] rounded-full animate-pulse"></div>
          <svg viewBox="0 0 100 100" className="w-full h-full transform -rotate-90">
            <circle cx="50" cy="50" r="45" fill="transparent" stroke="rgba(255,255,255,0.05)" strokeWidth="6" />
            <circle 
              cx="50" cy="50" r="45" 
              fill="transparent" 
              stroke="#7fa365" 
              strokeWidth="6" 
              strokeDasharray="283" 
              strokeDashoffset={283 - (283 * completedCount / 7)}
              strokeLinecap="round"
              className="transition-all duration-1000 ease-out"
