import { GoogleGenAI, Type, Modality } from "@google/genai";
import { DailyLog, Recipe, DailyContent } from "../types";

// Initialize the Google GenAI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_RULES = "As receitas devem ser OBRIGATORIAMENTE: Sem Glúten, Sem Leite e Sem Açúcar. O jantar deve ser leve e idealmente concluído até as 20h. É fundamental recomendar 15 minutos de sol entre 12h e 14h diariamente.";

/**
 * Generates daily content including menu, motivation, and challenge.
 */
export async function generateDailyContent(): Promise<DailyContent | null> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Gere um menu diário de 3 refeições. ${SYSTEM_RULES} O guia deve sugerir que o jejum comece após o jantar.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            menu: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  title: { type: Type.STRING },
                  ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
                  instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
                  prepTime: { type: Type.STRING }
                },
                required: ["type", "title", "ingredients", "instructions"]
              }
            },
            motivation: { type: Type.STRING },
            dailyChallenge: { type: Type.STRING }
          },
          required: ["menu", "motivation", "dailyChallenge"]
        }
      }
    });
    return JSON.parse(response.text || "null");
  } catch (error) {
    console.error("Error generating daily content:", error);
    return null;
  }
}

