                        </div>
                        <span className="text-xs font-bold text-white">{completedSteps} / 8</span>
                      </div>
                      <button onClick={() => handleEditPastLog(log.date)} className="flex items-center gap-2 text-[10px] font-bold text-ethereal-400 hover:text-white transition-all">Revisitar Dia <ChevronRight size={10} /></button>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

