import { GoogleGenAI, Type, Modality } from "@google/genai";
import { DailyLog, Recipe, DailyContent } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_RULES = "As refeições devem ser Sem Glúten, Sem Leite e Sem Açúcar. PROTOCOLO DE JEJUM: Recomende pular o café da manhã ou fazê-lo o mais tarde possível para estender o jejum. RITUAL DO ALHO: Sugira cortar o alho em 2 a 3 lâminas finas e engolir como comprimidos em jejum (evita hálito). SHOTS: Sugira shots anti-inflamatórios (limão, cúrcuma, gengibre, própolis). TRÍADE SAGRADA: Almoço e Jantar precoce (até 20h). Vitaminas proteicas opcionais à tarde.";

export async function generateDailyContent(): Promise<DailyContent | null> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Gere um menu diário (Almoço, Jantar e 2 Vitaminas Opcionais). Inclua 1 receita de Shot Anti-inflamatório. Reforce o jejum matinal e a técnica do alho comprimido. ${SYSTEM_RULES}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            menu: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  title: { type: Type.STRING },
                  ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
                  instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
                  prepTime: { type: Type.STRING }
                },
                required: ["type", "title", "ingredients", "instructions"]
              }
            },
            motivation: { type: Type.STRING },
            dailyChallenge: { type: Type.STRING }
          },
          required: ["menu", "motivation", "dailyChallenge"]
        }
      }
    });
    return JSON.parse(response.text || "null");
  } catch (error) {
    console.error("Error generating daily content:", error);
    return null;
  }
}

