export async function analyzeUserLogs(logs: DailyLog[]): Promise<string> {
  try {
    const context = JSON.stringify(logs.slice(-5));
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Insight espiritual (15 palavras) baseado nos logs: ${context}`,
    });
    return response.text || "Sua jornada é sagrada.";
  } catch (error) { return "Siga em paz."; }
}

export async function generateAppCover(): Promise<string | null> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: [{ text: "A mystical ethereal landscape of healing and reconnection, high resolution." }] },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) { return null; }
}

export async function generateSpeech(text: string): Promise<string | null> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
  } catch (error) { return null; }
}

