  { id: 'other', name: 'Outros (descreva na reflexão)', category: 'outro', weight: 1 },
];

interface TrackerProps {
  onSaveLog: (log: DailyLog) => void;
  logs: DailyLog[];
}

const Tracker: React.FC<TrackerProps> = ({ onSaveLog, logs }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [meals, setMeals] = useState({ breakfast: '', lunch: '', dinner: '', snacks: '' });
  const [reflection, setReflection] = useState('');
  const [symptoms, setSymptoms] = useState<string[]>([]);
  const [mood, setMood] = useState(3);
  const [waterGlasses, setWaterGlasses] = useState(0);

  const [habits, setHabits] = useState({
    diet: false,
    meditation: false,
    exercise: false,
    earthing: false,
    emotionalWork: false,
    sunExposure: false,
    sacredShot: false
  });

  const sortedLogs = useMemo(() => {
    return [...logs].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [logs]);

  const soulPrompt = useMemo(() => {
    if (symptoms.length === 0) return null;
    const selectedNames = SYMPTOMS
      .filter(s => symptoms.includes(s.id))
      .map(s => s.name.toLowerCase())
      .join(', ');
    return `Sua alma sente hoje ${selectedNames}. Como você honra isso em sua jornada?`;
  }, [symptoms]);

  useEffect(() => {
    const existingLog = logs.find(l => l.date === date);
    if (existingLog) {
      setMeals(existingLog.meals);
      setReflection(existingLog.reflection || '');
      setSymptoms(existingLog.symptomsPresent || []);
      setMood(existingLog.mood);
      setWaterGlasses(existingLog.waterIntake || 0);
      setHabits({
        diet: existingLog.completedActions.diet,
        meditation: existingLog.completedActions.meditationOrBreathing,
        exercise: existingLog.completedActions.exercise,
        earthing: existingLog.completedActions.earthing,
        emotionalWork: existingLog.completedActions.emotionalWork,
        sunExposure: existingLog.completedActions.sunExposure,
        sacredShot: existingLog.completedActions.sacredShot
      });
    } else {
      setMeals({ breakfast: '', lunch: '', dinner: '', snacks: '' });
      setReflection('');
      setSymptoms([]);
      setMood(3);
      setWaterGlasses(0);
      setHabits({ diet: false, meditation: false, exercise: false, earthing: false, emotionalWork: false, sunExposure: false, sacredShot: false });
    }
  }, [date, logs]);

  const handleSave = () => {
    onSaveLog({
      date,
      meals,
      reflection,
      symptomsPresent: symptoms,
      mood,
      waterIntake: waterGlasses,
      completedActions: { 
        ...habits,
        diet: habits.diet,
        diary: reflection.length > 5, 
        meditationOrBreathing: habits.meditation,
        waterGoal: waterGlasses >= 8,
        sunExposure: habits.sunExposure,
        sacredShot: habits.sacredShot
      }
    });
    alert(`Jornada atualizada e Alma ouvida! ✨`);
  };

  const handleEditPastLog = (pastDate: string) => {
    setDate(pastDate);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const journeyHabits = [
    { id: 'sacredShot', label: 'Alquimia (Alho/Shot)', icon: FlaskConical },
    { id: 'diet', label: 'Nutrição Limpa', icon: Leaf },
    { id: 'sunExposure', label: 'Banho de Sol', icon: Sun },
    { id: 'meditation', label: 'Meditação/Respiração', icon: Wind },
    { id: 'exercise', label: 'Movimento Físico', icon: Target },
    { id: 'earthing', label: 'Conexão Terra', icon: Map },
    { id: 'emotionalWork', label: 'Cura Emocional', icon: Heart },
  ];

  return (
    <div className="p-4 pb-40 max-w-2xl mx-auto space-y-12 animate-in fade-in duration-500">
      <header className="px-4">
        <h2 className="text-4xl font-serif text-white tracking-tight">Recordatário</h2>
      </header>

      <div className="glass-mystic p-6 rounded-[3rem] border border-white/10 mx-2 flex justify-between items-center shadow-xl">
        <div className="flex items-center gap-4">
          <CalendarDays className="text-nature-400" size={20} />
          <div>
            <span className="text-[10px] font-black uppercase text-ethereal-600 block">Registro do dia:</span>
            <span className="text-white font-serif text-lg">{new Date(date + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}</span>
          </div>
        </div>
        <div className="relative">
          <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="absolute inset-0 opacity-0 cursor-pointer" />
          <div className="p-3 bg-white/5 rounded-2xl border border-white/10 text-white"><Edit3 size={18} /></div>
        </div>
      </div>

      <div className="space-y-10">
        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-6">
           <h3 className="font-serif text-2xl text-white">Reflexão da Alma</h3>
           <textarea 
             className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-6 text-sm text-white focus:border-magic-gold/50 outline-none resize-none placeholder:text-ethereal-800 italic"
             placeholder="Como sua essência se sente hoje?"
             rows={5}
             value={reflection}
             onChange={(e) => setReflection(e.target.value)}
           />
        </section>

        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-6">
           <h3 className="font-serif text-2xl text-white">Objetivos Alcançados</h3>
           <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
             {journeyHabits.map(habit => (
               <button
                 key={habit.id}
                 onClick={() => setHabits(prev => ({ ...prev, [habit.id]: !prev[habit.id as keyof typeof habits] }))}
                 className={`p-4 rounded-2xl border transition-all flex items-center gap-4 text-left ${
                   habits[habit.id as keyof typeof habits] 
                     ? 'bg-nature-900/40 border-nature-400/50 text-white' 
                     : 'bg-white/5 border-white/5 text-ethereal-600'
                 }`}
               >
                 <habit.icon size={16} />
                 <span className="text-[10px] font-black uppercase tracking-widest">{habit.label}</span>
               </button>
             ))}
           </div>
        </section>

        <button 
           onClick={handleSave}
           className="w-full bg-nature-500 text-white py-6 rounded-[3rem] font-bold text-lg flex items-center justify-center gap-4 shadow-2xl active:scale-95 transition-transform"
        >
           <Save size={24} /> Eternizar Relato
        </button>
      </div>
    </div>
  );
};

