      id: 'exercise', 
      label: 'Movimento Vital', 
      completed: todayLog?.completedActions.exercise, 
      icon: Footprints, 
      type: 'action',
      description: 'Honre seu corpo físico através do movimento, despertando a força interior.'
    },
    { 
      id: 'earthing', 
      label: 'Conexão Terra', 
      completed: todayLog?.completedActions.earthing, 
      icon: Mountain, 
      type: 'action',
      description: 'Descarregue o excesso e recarregue sua energia em contato direto com a natureza.'
