              <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">Vídeo Curto</span>
              <input type="file" ref={videoInputRef} hidden accept="video/*" capture="user" onChange={handleVideoSelect} />
            </button>
          </div>
          <button 
            onClick={handlePost}
            disabled={isUploading || (!newPost.trim() && !mediaPreview)}
            className="bg-nature-800 text-white px-8 py-2.5 rounded-full font-bold text-xs shadow-lg shadow-nature-100 hover:bg-nature-900 active:scale-95 disabled:opacity-50 transition-all flex items-center gap-2"
          >
            {isUploading ? <><Sparkles size={14} className="animate-spin" /> ...</> : <><Send size={14} /> Postar</>}
          </button>
        </div>
      </div>

      {/* Feed Filters */}
      <div className="flex gap-2 px-1">
        {(['recent', 'liked', 'following'] as FilterType[]).map(f => (
          <button
            key={f}
            onClick={() => setActiveFilter(f)}
            className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border ${
              activeFilter === f 
                ? 'bg-nature-800 text-white border-nature-800 shadow-md' 
                : 'bg-white text-nature-400 border-nature-100 hover:border-nature-300'
            }`}
          >
            {f === 'recent' ? 'Recentes' : f === 'liked' ? 'Destaques' : 'Minha Tribo'}
          </button>
        ))}
      </div>

      {/* Posts List */}
      <div className="space-y-8">
        {filteredPosts.map(post => (
          <div key={post.id} className="bg-white rounded-[2.5rem] shadow-sm border border-nature-50 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500 relative">
