const Wellness: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'breathing' | 'meditation' | 'emotional' | 'healing-ritual'>('breathing');
  const [loading, setLoading] = useState(false);
  const [loadingItem, setLoadingItem] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [activeMeditation, setActiveMeditation] = useState<string | null>(null);

  const [activePattern, setActivePattern] = useState(BREATHING_PATTERNS[0]);
  const [breathPhase, setBreathPhase] = useState<'inhale' | 'hold1' | 'exhale' | 'hold2' | 'idle'>('idle');
  const [breathTimer, setBreathTimer] = useState(0);

  const [ritualStep, setRitualStep] = useState<'idle' | 'preparing' | 'breathing' | 'feeling' | 'forgiving' | 'affirming' | 'checking' | 'completed'>('idle');
  const [activeRitualId, setActiveRitualId] = useState<string | null>(null);
  const [isEyesClosed, setIsEyesClosed] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const sourceRef = useRef<AudioBufferSourceNode | null>(null);
  const intervalRef = useRef<number | null>(null);

  const initAudio = async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      gainNodeRef.current = audioContextRef.current.createGain();
      gainNodeRef.current.gain.value = 1.5;
      gainNodeRef.current.connect(audioContextRef.current.destination);
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }
    return audioContextRef.current;
  };

  const stopPractice = () => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    if (sourceRef.current) {
      try { 
        sourceRef.current.onended = null;
        sourceRef.current.stop(); 
      } catch(e) {}
      sourceRef.current = null;
    }
    setIsPlaying(false);
    setBreathPhase('idle');
    setLoading(false);
    setLoadingItem(null);
    setActiveMeditation(null);
    setIsEyesClosed(false);
    setRitualStep('idle');
  };

  const playBase64Audio = async (base64: string) => {
    if (!base64) return;
    const ctx = await initAudio();
    const buffer = await decodeAudioData(decodeBase64(base64), ctx);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(gainNodeRef.current!);
    source.start();
    sourceRef.current = source;
    return new Promise((resolve) => {
      source.onended = () => {
        sourceRef.current = null;
        resolve(true);
      };
    });
  };

  const startBreathing = async () => {
    stopPractice();
    await initAudio();
    setIsPlaying(true);
    let currentPhase: any = 'inhale';
    setBreathPhase(currentPhase);
    setBreathTimer(activePattern.inhale);

    const playGuidance = async (text: string) => {
      const b64 = await generateSpeech(text);
      if (b64) await playBase64Audio(b64);
    };

    playGuidance("Inspire.");

    intervalRef.current = window.setInterval(async () => {
      setBreathTimer(prev => {
        if (prev > 1) return prev - 1;

        if (currentPhase === 'inhale') {
          if (activePattern.hold1 > 0) {
            currentPhase = 'hold1';
            setBreathTimer(activePattern.hold1);
            playGuidance("Segure.");
          } else {
            currentPhase = 'exhale';
            setBreathTimer(activePattern.exhale);
            playGuidance("Exale.");
          }
        } else if (currentPhase === 'hold1') {
          currentPhase = 'exhale';
          setBreathTimer(activePattern.exhale);
          playGuidance("Exale.");
        } else if (currentPhase === 'exhale') {
          if (activePattern.hold2 > 0) {
            currentPhase = 'hold2';
            setBreathTimer(activePattern.hold2);
            playGuidance("Vazio.");
          } else {
            currentPhase = 'inhale';
            setBreathTimer(activePattern.inhale);
            playGuidance("Inspire.");
          }
        } else if (currentPhase === 'hold2') {
          currentPhase = 'inhale';
          setBreathTimer(activePattern.inhale);
          playGuidance("Inspire.");
        }
        setBreathPhase(currentPhase);
        return prev;
      });
    }, 1000);
  };

  const handleMeditationSelect = async (focus: string) => {
    stopPractice();
    setLoading(true);
    setLoadingItem(focus);
    setActiveMeditation(focus);

    try {
      const audioB64 = await generateAndPlayMeditationAudio(focus);
      if (audioB64) {
        setIsPlaying(true);
        await playBase64Audio(audioB64);
      }
    } finally {
      setLoading(false);
      setLoadingItem(null);
      setIsPlaying(false);
      setActiveMeditation(null);
    }
  };

  const handleAffirmation = async () => {
    const input = document.getElementById('feeling-input') as HTMLInputElement;
    const feeling = input?.value || 'Paz';
    stopPractice();
    setLoading(true);
    try {
      const audioB64 = await generateAndPlayAffirmationAudio(feeling);
      if (audioB64) await playBase64Audio(audioB64);
    } finally {
      setLoading(false);
    }
  };

  const startHealingRitual = async (ritualId: string) => {
    const ritual = GUIDED_RITUALS.find(r => r.id === ritualId);
    if (!ritual) return;

    stopPractice();
    setLoading(true);
    setActiveRitualId(ritualId);
    setRitualStep('preparing');
    setIsEyesClosed(true);

    const sequence: (keyof typeof ritual.steps)[] = Object.keys(ritual.steps) as any;

    try {
      for (const step of sequence) {
        setRitualStep(step as any);
        const b64 = await generateSpeech(ritual.steps[step as keyof typeof ritual.steps]!);
        if (b64) await playBase64Audio(b64);
      }
      setRitualStep('completed');
    } catch (e) {
      setRitualStep('idle');
    } finally {
      setLoading(false);
      setIsEyesClosed(false);
    }
  };

  const handleTabChange = (tab: any) => {
    setActiveTab(tab);
    stopPractice();
  };

  return (
    <div className="p-4 pb-32 max-w-2xl mx-auto space-y-10">
      <header className="px-4 text-center">
        <h2 className="text-4xl font-serif text-white tracking-tighter">Santuário Sagrado</h2>
        <p className="text-nature-400 text-xs uppercase tracking-[0.4em] font-black mt-2">Reconexão com a Essência</p>
      </header>

      <div className="flex glass-mystic p-1 rounded-3xl gap-1 mx-4">
        {[
          { id: 'breathing', label: 'Pulsar', icon: Wind },
          { id: 'meditation', label: 'Vibrar', icon: Flower2 },
          { id: 'emotional', label: 'Afirmar', icon: Heart },
          { id: 'healing-ritual', label: 'Curar', icon: Sparkle }
        ].map(t => (
          <button 
            key={t.id}
            onClick={() => handleTabChange(t.id as any)}
            className={`flex-1 py-3 flex flex-col items-center gap-1 rounded-2xl transition-all ${activeTab === t.id ? 'bg-white text-nature-900 shadow-xl' : 'text-ethereal-400'}`}
          >
            <t.icon size={16} />
            <span className="text-[9px] font-black uppercase tracking-widest">{t.label}</span>
          </button>
        ))}
      </div>

      {activeTab === 'breathing' && (
        <div className="space-y-12 animate-in fade-in duration-1000">
           <div className="relative flex flex-col items-center justify-center py-10 min-h-[400px]">
              <div className="absolute inset-0 flex items-center justify-center overflow-hidden pointer-events-none">
                 <div className={`w-64 h-64 rounded-full border border-nature-400/20 transition-all duration-[4000ms] ${breathPhase === 'inhale' ? 'scale-[2.5] opacity-100' : 'scale-50 opacity-0'}`} />
                 <div className="absolute w-40 h-40 bg-nature-400/10 rounded-full blur-3xl animate-pulse" />
              </div>

              <div className={`w-48 h-48 glass-mystic rounded-full flex flex-col items-center justify-center relative z-10 transition-all duration-1000 ${breathPhase !== 'idle' ? 'border-nature-400 shadow-[0_0_60px_rgba(127,163,101,0.2)]' : 'border-white/5'}`}>
                 <span className="text-6xl font-serif text-white mb-2">{breathPhase === 'idle' ? <Wind size={60} className="text-nature-300" /> : breathTimer}</span>
                 <span className="text-[10px] font-black uppercase tracking-[0.3em] text-nature-400">
                   {breathPhase === 'inhale' ? 'Inspire' : breathPhase === 'hold1' ? 'Segure' : breathPhase === 'exhale' ? 'Exale' : breathPhase === 'hold2' ? 'Vazio' : 'Respire'}
                 </span>
              </div>

              <div className="mt-12 text-center z-10">
                <h3 className="text-2xl font-serif text-white">{activePattern.name}</h3>
                <p className="text-ethereal-500 italic text-sm mt-1">{activePattern.desc}</p>
              </div>
           </div>

           <div className="grid grid-cols-2 gap-4 px-4">
              {BREATHING_PATTERNS.map(p => (
                <button 
                  key={p.id}
                  onClick={() => { setActivePattern(p); stopPractice(); }}
                  className={`p-5 rounded-[2rem] border transition-all text-left ${activePattern.id === p.id ? 'bg-nature-900 border-nature-400' : 'glass-mystic border-white/5'}`}
                >
                  <h4 className="font-bold text-white text-sm">{p.name}</h4>
                  <p className="text-[10px] text-ethereal-500 mt-1 uppercase tracking-widest">{p.inhale}-{p.hold1}-{p.exhale}-{p.hold2}</p>
                </button>
              ))}
           </div>

           <div className="px-6 space-y-4">
             <button 
                onClick={isPlaying ? stopPractice : startBreathing}
                className={`w-full py-5 rounded-3xl font-bold transition-all shadow-2xl flex items-center justify-center gap-3 ${isPlaying ? 'bg-nature-800 text-white' : 'bg-white text-nature-950 hover:scale-[1.02]'}`}
             >
                {isPlaying ? <><Square size={20} fill="currentColor"/> Parar</> : <><Play size={24} fill="currentColor" /> Pulsar</>}
             </button>
           </div>
        </div>
      )}

      {activeTab === 'meditation' && (
        <div className="bg-white/5 glass-mystic p-8 rounded-[3rem] space-y-8 animate-in fade-in duration-500 mx-4">
          <div className="flex items-center gap-3"><Flower2 className="text-nature-500" /><h3 className="font-serif text-xl text-white">Viagem ao Centro do Ser</h3></div>
          <p className="text-ethereal-400 text-sm italic">Áudio guiado instantâneo com volume amplificado.</p>
          <div className="grid grid-cols-1 gap-4">
            {['Luz Interior e Presença', 'Gratidão e Abundância', 'Foco e Clareza Mental'].map(f => (
                <button 
                    key={f} 
                    disabled={loading}
                    onClick={() => handleMeditationSelect(f)}
                    className={`w-full glass-mystic border p-5 rounded-2xl text-left transition-all group relative overflow-hidden ${
                      activeMeditation === f ? 'border-nature-400 bg-nature-900/50' : 'border-white/5'
                    } ${loading && loadingItem !== f ? 'opacity-30' : ''}`}
                >
                    <div className="flex justify-between items-center text-white relative z-10">
                        <span className="text-sm font-bold">{f}</span>
                        {loadingItem === f ? <Loader2 className="animate-spin text-nature-400" size={18}/> : <Play size={16} className="text-nature-400" />}
                    </div>
                </button>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'emotional' && (
        <div className="bg-white/5 glass-mystic p-8 rounded-[3rem] space-y-6 mx-4 animate-in fade-in">
          <div className="flex items-center gap-3"><Heart className="text-nature-500" /><h3 className="font-serif text-xl text-white">Espelho da Alma</h3></div>
          <p className="text-ethereal-400 text-sm italic">Sua afirmação de cura, falada com clareza agora.</p>
          <input type="text" id="feeling-input" placeholder="Ex: Medo, Ansiedade..." className="w-full p-4 rounded-xl glass-mystic text-sm text-white focus:outline-none border border-white/5 focus:border-nature-400 transition-all" />
          <button disabled={loading} onClick={handleAffirmation} className="w-full bg-white text-nature-950 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg transition-all active:scale-95 disabled:opacity-50">
            {loading ? <Loader2 className="animate-spin" /> : <><Zap size={18} /> Afirmar Agora</>}
          </button>
        </div>
      )}

      {activeTab === 'healing-ritual' && (
        <div className="px-4 space-y-8 animate-in slide-up">
          {ritualStep === 'idle' ? (
            <div className="space-y-6">
              <div className="px-4 space-y-2">
                <h3 className="text-2xl font-serif text-white">Rituais de Cura Guiada</h3>
                <p className="text-xs text-ethereal-400 italic">Práticas místicas para harmonizar seu templo interior.</p>
              </div>

              <div className="grid grid-cols-1 gap-4">
                {GUIDED_RITUALS.map((ritual) => (
                  <div key={ritual.id} className="glass-mystic p-6 rounded-[2.5rem] border border-white/5 space-y-4 hover:border-white/10 transition-all group">
                    <div className="flex items-start justify-between">
                      <div className="flex items-center gap-3">
                        <div className={`p-3 rounded-2xl bg-white/5 ${ritual.color}`}>
                          <ritual.icon size={24} />
