                        <div>
                          <h4 className="text-lg font-serif text-white">{ritual.title}</h4>
                          <p className="text-[10px] font-black uppercase tracking-widest text-ethereal-500">Prática Sagrada</p>
                        </div>
                      </div>
                    </div>
                    <p className="text-xs text-ethereal-300 leading-relaxed italic pr-4">
                      {ritual.desc}
                    </p>
                    <button 
                      onClick={() => startHealingRitual(ritual.id)}
                      disabled={loading}
                      className="w-full py-4 bg-white text-nature-950 rounded-2xl font-bold text-xs uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl hover:scale-[1.02] active:scale-95 transition-all"
                    >
                      {loading && loadingItem === ritual.id ? <Loader2 className="animate-spin" size={16} /> : <><Play size={14} fill="currentColor" /> Iniciar Ritual</>}
                    </button>
                  </div>
                ))}
              </div>
            </div>
          ) : ritualStep === 'completed' ? (
            <div className="glass-mystic p-12 rounded-[4rem] text-center space-y-8 animate-in zoom-in border border-nature-500/20">
                <div className="relative w-24 h-24 mx-auto">
                   <div className="absolute inset-0 bg-nature-400/20 blur-2xl rounded-full animate-pulse" />
                   <div className="relative w-full h-full bg-nature-400/20 rounded-full flex items-center justify-center text-nature-400 border border-nature-400/30">
                      <CheckCircle size={48} />
                   </div>
