            <div className={`glass-mystic p-10 rounded-[4rem] text-center space-y-12 min-h-[500px] flex flex-col items-center justify-center relative transition-all duration-1000 border border-white/10 ${isEyesClosed ? 'bg-nature-950' : ''}`}>
               <div className="absolute top-8 left-1/2 -translate-x-1/2">
                  <div className="flex items-center gap-2 text-magic-gold animate-pulse">
                     <Sparkles size={14} />
                     <span className="text-[10px] font-black uppercase tracking-[0.3em]">Ritual em Curso</span>
                  </div>
               </div>

               <div className="relative w-48 h-48 flex items-center justify-center">
                  <div className="absolute inset-0 bg-nature-400/10 blur-[60px] rounded-full animate-breath" />
                  <div className="w-full h-full glass-mystic rounded-full flex items-center justify-center border border-white/10 relative z-10">
                    {ritualStep === 'preparing' && <Loader2 size={48} className="text-nature-400 animate-spin" />}
                    {ritualStep === 'breathing' && <Wind size={64} className="text-nature-400 animate-breath" />}
                    {ritualStep === 'feeling' && <EyeOff size={64} className="text-ethereal-400 animate-pulse" />}
                    {ritualStep === 'forgiving' && <Heart size={64} className="text-rose-400 animate-pulse" />}
                    {ritualStep === 'affirming' && <Zap size={64} className="text-magic-gold animate-pulse" />}
                    {ritualStep === 'checking' && <Circle size={64} className="text-indigo-400 animate-breath" />}
                  </div>
               </div>

               <div className="space-y-6">
                 <h4 className="text-3xl font-serif text-white capitalize tracking-wide">
                   {ritualStep === 'preparing' ? 'Preparando...' : 
                    ritualStep === 'breathing' ? 'Respire' : 
                    ritualStep === 'feeling' ? 'Sinta' : 
                    ritualStep === 'forgiving' ? 'Perdoe' : 
                    ritualStep === 'affirming' ? 'Afirme' : 'Integre'}
