                       ))}
                    </div>
                 </div>
               </div>

               <button 
                 onClick={stopPractice} 
                 className="p-4 bg-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest text-red-400/60 hover:text-red-400 transition-all border border-white/5"
