import { 
  CheckCircle2, 
  Sparkles, 
  Wind, 
  Footprints, 
  Leaf, 
  Droplets, 
  Scroll, 
  Mountain, 
  Heart, 
  Star, 
  CalendarDays, 
  Lock, 
  Circle, 
  Target, 
  Bell, 
  BellOff, 
  Zap,
  Sunrise,
  Info,
  Sun,
  FlaskConical,
  TrendingUp
} from 'lucide-react';
import React, { useEffect, useState, useMemo } from 'react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';
import { analyzeUserLogs } from '../services/geminiService';
import { requestNotificationPermission, sendPresenceReminder } from '../services/notificationService';
import { DailyLog, UserProfile } from '../types';

interface DashboardProps {
  userProfile: UserProfile;
  logs: DailyLog[];
  onToggleGoal: (goalKey: keyof DailyLog['completedActions']) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ userProfile, logs, onToggleGoal }) => {
  const [insight, setInsight] = useState<string | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);
  const [notificationsActive, setNotificationsActive] = useState(false);
  const [hoveredGoal, setHoveredGoal] = useState<string | null>(null);

  const todayStr = new Date().toISOString().split('T')[0];
  const todayLog = logs.find(l => l.date === todayStr);

  const todaysGoals = useMemo(() => {
    const goals = [
      { 
        id: 'sacredShot', 
        label: 'Shot de Despertar', 
        completed: todayLog?.completedActions.sacredShot, 
        icon: FlaskConical, 
        type: 'action',
        description: 'Inicie com o alho comprimido (laminado) ou um shot anti-inflamatório para purificar o templo em jejum.' 
      },
      { 
        id: 'diet', 
        label: 'Nutrição Sagrada', 
        completed: todayLog?.completedActions.diet, 
        icon: Leaf, 
        type: 'action',
        description: 'Almoço e jantar precoce sem glúten, leite ou açúcar. Tente postergar a primeira refeição.' 
      },
      { 
        id: 'waterGoal', 
        label: 'Água Cristalina', 
        completed: todayLog?.completedActions.waterGoal, 
        icon: Droplets, 
        type: 'action',
        description: 'Hidrate suas células e limpe toxinas para manter o fluxo de energia vital.'
      },
      { 
        id: 'sunExposure', 
        label: 'Banho de Sol Vital', 
        completed: todayLog?.completedActions.sunExposure, 
        icon: Sun, 
        type: 'action',
        description: '15 minutos de sol entre 12h e 14h para ativar sua vitamina D e sincronizar seu ritmo interno.' 
      },
      { 
        id: 'meditationOrBreathing', 
        label: 'Respiração Cósmica', 
        completed: todayLog?.completedActions.meditationOrBreathing, 
        icon: Wind, 
        type: 'action',
        description: 'Silencie a mente e conecte-se com o agora através da respiração consciente.'
      },
      { 
        id: 'exercise', 
        label: 'Movimento Vital', 
        completed: todayLog?.completedActions.exercise, 
        icon: Footprints, 
        type: 'action',
        description: 'Honre seu corpo físico através do movimento, despertando a força interior.'
      },
      { 
        id: 'earthing', 
        label: 'Conexão Terra', 
        completed: todayLog?.completedActions.earthing, 
        icon: Mountain, 
        type: 'action',
        description: 'Descarregue o excesso e recarregue sua energia em contato direto com a natureza.'
      },
      { 
        id: 'diary', 
        label: 'Relato da Alma', 
        completed: todayLog?.completedActions.diary, 
        icon: Scroll, 
        type: 'status',
        description: 'Documente sua jornada para integrar aprendizados e observar sua própria evolução.'
      },
    ];

    // Reordena: Ações primeiro, Status depois
    return goals.sort((a, b) => {
      if (a.type === 'action' && b.type === 'status') return -1;
      if (a.type === 'status' && b.type === 'action') return 1;
      return 0;
    });
  }, [todayLog]);

  const totalGoals = todaysGoals.length;
  const completedCount = todaysGoals.filter(g => g.completed).length;
  const hasStartedDay = completedCount > 0;

  const journeyData = useMemo(() => {
    if (!logs.length) return [];
    return logs
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .slice(-7)
      .map(log => {
        const completed = Object.values(log.completedActions).filter(Boolean).length;
        const total = Object.keys(log.completedActions).length;
        return {
          day: new Date(log.date + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
          percent: Math.round((completed / total) * 100),
        };
      });
  }, [logs]);

  useEffect(() => {
    const fetchInsight = async () => {
      if (logs.length >= 2 && !insight) {
        setLoadingInsight(true);
        const result = await analyzeUserLogs(logs);
        setInsight(result);
        setLoadingInsight(false);
      }
    };
    fetchInsight();

    if ("Notification" in window) {
      setNotificationsActive(Notification.permission === "granted");
    }
  }, [logs]);

  const handleToggleNotifications = async () => {
    const granted = await requestNotificationPermission();
    setNotificationsActive(granted);
    if (granted) {
      sendPresenceReminder(
        "Presença Ativada ✨", 
        "Agora você receberá lembretes para honrar sua essência todos os dias."
      );
    }
  };

  return (
    <div className="p-6 pb-32 max-w-2xl mx-auto space-y-12 animate-in fade-in duration-1000 relative overflow-hidden">
      <div className="absolute top-20 right-0 w-64 h-64 bg-nature-400/5 blur-[120px] rounded-full pointer-events-none" />

      <header className="flex justify-between items-start relative z-10">
        <div className="space-y-1">
          <p className="text-nature-400 font-black text-[10px] uppercase tracking-[0.4em]">Portal de Presença</p>
          <h2 className="text-4xl font-serif text-white leading-tight">Olá, {userProfile.name}</h2>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleToggleNotifications}
            className={`p-3 rounded-2xl border transition-all ${notificationsActive ? 'bg-nature-500/20 border-nature-400/30 text-nature-400' : 'bg-white/5 border-white/10 text-ethereal-500 hover:text-white'}`}
            title={notificationsActive ? "Lembretes Ativos" : "Ativar Lembretes Diários"}
          >
            {notificationsActive ? <Bell size={18} /> : <BellOff size={18} />}
          </button>
          <div className="glass-mystic text-white px-4 py-2 rounded-2xl flex items-center gap-2 border border-white/10">
            <Star size={14} className="text-nature-300" />
            <span className="text-[10px] font-bold uppercase tracking-widest">Dia {Math.floor((new Date().getTime() - new Date(userProfile.startDate!).getTime()) / (1000 * 3600 * 24)) + 1}</span>
          </div>
        </div>
      </header>

      {!hasStartedDay && (
        <section className="animate-in slide-in-from-top-4 duration-1000">
           <div className="relative p-8 rounded-[3rem] overflow-hidden border border-magic-gold/20 shadow-[0_20px_50px_rgba(212,175,55,0.1)] bg-gradient-to-br from-nature-950/80 to-ethereal-950/80 backdrop-blur-xl group">
              <div className="absolute -top-10 -right-10 w-40 h-40 bg-magic-gold/10 rounded-full blur-[40px] group-hover:bg-magic-gold/20 transition-all" />
              <div className="relative z-10 flex flex-col gap-4">
                 <div className="flex items-center gap-3">
                    <div className="p-3 bg-magic-gold/20 rounded-2xl text-magic-gold">
                       <Sunrise size={24} className="animate-pulse" />
                    </div>
                    <div>
                       <h3 className="text-xl font-serif text-white leading-tight">Ritual de Despertar</h3>
                       <p className="text-[10px] font-black text-magic-gold uppercase tracking-widest">Ação Necessária</p>
                    </div>
                 </div>
                 <p className="text-sm text-ethereal-300 italic leading-relaxed">
                   O sol despertou sua essência. Lembre-se do seu <strong>Banho de Sol</strong> e firme suas intenções para hoje.
                 </p>
                 <button 
                   onClick={() => document.getElementById('intentions-section')?.scrollIntoView({ behavior: 'smooth' })}
                   className="w-fit flex items-center gap-2 px-6 py-3 bg-magic-gold text-nature-950 rounded-2xl font-bold text-xs uppercase tracking-widest hover:scale-105 transition-transform active:scale-95"
                 >
                   Firmar Intenções <Zap size={14} />
                 </button>
              </div>
           </div>
        </section>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 items-stretch">
        <section className="relative flex flex-col items-center justify-center py-8 glass-mystic rounded-[4rem] border border-white/5 shadow-inner bg-nature-950/20">
          <div className="relative w-40 h-40 flex items-center justify-center">
            <div className="absolute inset-0 bg-nature-500/10 blur-[40px] rounded-full animate-pulse"></div>
            <svg viewBox="0 0 100 100" className="w-full h-full transform -rotate-90">
              <circle cx="50" cy="50" r="45" fill="transparent" stroke="rgba(255,255,255,0.05)" strokeWidth="6" />
              <circle 
                cx="50" cy="50" r="45" 
                fill="transparent" 
                stroke="#7fa365" 
                strokeWidth="6" 
                strokeDasharray="283" 
                strokeDashoffset={283 - (283 * completedCount / totalGoals)}
                strokeLinecap="round"
                className="transition-all duration-1000 ease-out"
              />
            </svg>
            <div className="absolute flex flex-col items-center">
              <span className="text-4xl font-serif font-bold text-white">{completedCount}</span>
              <span className="text-[8px] font-black text-nature-400 uppercase tracking-widest">Ativadas</span>
            </div>
          </div>
          <div className="mt-6 text-center space-y-1">
             <p className="text-[10px] font-black text-ethereal-500 uppercase tracking-[0.3em]">Foco de Hoje</p>
          </div>
        </section>

        <section className="glass-mystic rounded-[3rem] border border-white/5 p-8 flex flex-col justify-between space-y-4">
          <div className="flex items-center justify-between px-2">
            <div className="flex items-center gap-2">
              <TrendingUp size={16} className="text-nature-400" />
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Jornada Evolutiva</h3>
            </div>
            <span className="text-[8px] font-medium text-ethereal-600 uppercase tracking-widest">Últimos 7 dias</span>
          </div>

          <div className="h-32 w-full mt-2">
            {journeyData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={journeyData}>
                  <defs>
                    <linearGradient id="colorPercent" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#7fa365" stopOpacity={0.3}/>
                      <stop offset="95%" stopColor="#7fa365" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <XAxis dataKey="day" hide />
                  <YAxis hide domain={[0, 100]} />
                  <Tooltip 
                    contentStyle={{ 
                      backgroundColor: 'rgba(13, 18, 11, 0.9)', 
                      borderRadius: '16px', 
                      border: '1px solid rgba(255,255,255,0.1)',
                      fontSize: '10px',
                      color: '#fff'
                    }}
                    itemStyle={{ color: '#7fa365' }}
                    labelStyle={{ color: '#94a3b8', marginBottom: '4px' }}
                    formatter={(value: number) => [`${value}%`, 'Concluído']}
                  />
                  <Area 
                    type="monotone" 
                    dataKey="percent" 
                    stroke="#7fa365" 
                    fillOpacity={1} 
                    fill="url(#colorPercent)" 
                    strokeWidth={2}
                  />
                </AreaChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-[10px] font-medium text-ethereal-700 italic">
                Aguardando mais registros...
              </div>
            )}
          </div>
          <div className="pt-2">
            <p className="text-[9px] text-ethereal-500 italic leading-relaxed">
              Visualize sua constância e o despertar do seu brilho interior ao longo do tempo.
            </p>
          </div>
        </section>
      </div>

      <section id="intentions-section" className="space-y-6">
        <div className="px-4 space-y-2">
          <div className="flex justify-between items-end">
            <h3 className="text-2xl font-serif text-white tracking-tight">Intenções Sagradas</h3>
            <Target size={18} className="text-nature-400 animate-pulse" />
          </div>
        </div>

        <div className="grid grid-cols-1 gap-3 px-2">
          {todaysGoals.map((goal, idx) => {
            const GoalIcon = goal.icon;
            const isStatus = goal.type === 'status';
            const isHovered = hoveredGoal === goal.id;

            return (
              <div key={idx} className="relative group">
                <button 
                  onClick={() => !isStatus && onToggleGoal(goal.id as any)}
                  disabled={isStatus}
                  className={`p-5 rounded-[2.5rem] flex items-center gap-5 border transition-all duration-300 text-left w-full active:scale-95 ${
                    goal.completed 
                      ? 'bg-nature-900/40 border-nature-500/30' 
                      : 'glass-mystic border-white/5 hover:border-nature-400/20'
                  } ${isStatus ? 'cursor-default opacity-80' : ''}`}
                >
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${
                    goal.completed ? 'bg-nature-500 text-nature-950 shadow-[0_0_15px_rgba(127,163,101,0.3)]' : 'bg-white/5 text-ethereal-600'
                  }`}>
                    {goal.completed ? <CheckCircle2 size={24} /> : <GoalIcon size={24} />}
                  </div>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <span className={`font-bold text-sm tracking-tight block ${goal.completed ? 'text-nature-400' : 'text-white'}`}>
                        {goal.label}
                      </span>
                      <div 
                        onMouseEnter={() => setHoveredGoal(goal.id)}
                        onMouseLeave={() => setHoveredGoal(null)}
                        className="cursor-help p-1 -m-1 inline-flex items-center justify-center"
                      >
                        <Info size={14} className="text-ethereal-700 opacity-60 hover:opacity-100 transition-opacity" />
                      </div>
                    </div>
                    <span className="text-[9px] text-ethereal-600 font-medium uppercase tracking-widest mt-0.5">
                      {goal.completed ? 'Intenção Manifestada' : goal.type === 'action' ? 'Firmar Intenção' : 'Aguardando Registro'}
                    </span>
                  </div>
                </button>

                {isHovered && (
                  <div className="absolute left-1/2 -bottom-2 -translate-x-1/2 translate-y-full w-[90%] z-20 pointer-events-none animate-in fade-in zoom-in duration-300">
                    <div className="glass-mystic p-4 rounded-3xl border border-nature-400/20 shadow-2xl bg-nature-950/95 backdrop-blur-xl text-center">
