        <div className="fixed bottom-0 left-0 w-full p-8 bg-gradient-to-t from-ethereal-950 via-ethereal-950 to-transparent z-50">
          <button 
            onClick={() => setStep('result')}
            disabled={selectedPhysical.length === 0 && selectedSpiritual.length === 0}
            className="w-full bg-white text-nature-950 py-6 rounded-[2.5rem] font-bold shadow-2xl disabled:opacity-20 transition-all active:scale-95"
          >
            Consolidar Diagnóstico
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="p-8 flex flex-col items-center justify-center min-h-screen animate-in zoom-in">
      <div className="text-center space-y-12 w-full max-w-sm">
        <div className="relative w-48 h-48 mx-auto">
          <div className="absolute inset-0 bg-magic-gold/10 blur-[50px] rounded-full animate-pulse" />
          <div className="relative w-full h-full glass-mystic rounded-full flex items-center justify-center border border-magic-gold/20 shadow-[0_0_30px_rgba(212,175,55,0.15)]">
             <div className="flex flex-col items-center">
                <span className="text-[10px] font-black uppercase tracking-widest text-magic-gold mb-1">Caminho de Cura</span>
                <h3 className="text-7xl font-serif font-bold text-white">
                  {Math.min(100, (selectedPhysical.length + selectedSpiritual.length) * 5)}%
