interface TrackerProps {
  onSaveLog: (log: DailyLog) => void;
  logs: DailyLog[];
}

const Tracker: React.FC<TrackerProps> = ({ onSaveLog, logs }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [reflection, setReflection] = useState('');
  const [synchronicities, setSynchronicities] = useState('');
  const [shadowObservations, setShadowObservations] = useState('');
  const [energyLevel, setEnergyLevel] = useState(3);
  const [awarenessLevel, setAwarenessLevel] = useState(3);

  const [habits, setHabits] = useState({
    silence: false,
    meditation: false,
    shadowWork: false,
    study: false,
    natureConnection: false,
    gratitude: false,
    presence: false,
    movement: false
  });

  useEffect(() => {
    const existingLog = logs.find(l => l.date === date);
    if (existingLog) {
      setReflection(existingLog.reflection || '');
      setSynchronicities(existingLog.synchronicities || '');
      setShadowObservations(existingLog.shadowObservations || '');
      setEnergyLevel(existingLog.energyLevel || 3);
      setAwarenessLevel(existingLog.awarenessLevel || 3);
      setHabits(existingLog.completedActions as any);
    } else {
      setReflection('');
      setSynchronicities('');
      setShadowObservations('');
      setEnergyLevel(3);
      setAwarenessLevel(3);
      setHabits({ silence: false, meditation: false, shadowWork: false, study: false, natureConnection: false, gratitude: false, presence: false, movement: false });
    }
  }, [date, logs]);

  const handleSave = () => {
    onSaveLog({
      date,
      spiritualPractices: { morning: '', afternoon: '', evening: '' },
      reflection,
      synchronicities,
      shadowObservations,
      energyLevel,
      awarenessLevel,
      completedActions: { ...habits, alkalinity: habits.presence, journaling: true } as any
    });
    alert(`Relato da Alma guardado com sucesso. ✨`);
  };

  const spiritualPractices = [
    { id: 'silence', label: 'Silêncio Sagrado', icon: Moon },
    { id: 'meditation', label: 'Portal de Autocura', icon: Sparkles },
    { id: 'shadowWork', label: 'Trabalho de Sombra', icon: Ghost },
    { id: 'study', label: 'Estudo Hermético', icon: Zap },
    { id: 'gratitude', label: 'Voto de Gratidão', icon: Heart },
    { id: 'presence', label: 'Presença Radical', icon: Eye },
  ];

  return (
    <div className="p-4 pb-40 max-w-2xl mx-auto space-y-12 animate-in fade-in">
      <header className="px-4 text-center">
        <h2 className="text-4xl font-serif text-white italic tracking-tighter">Livro de Espelhos</h2>
        <p className="text-magic-gold text-[10px] uppercase tracking-[0.4em] font-black mt-2">Documentando sua Autocura</p>
      </header>

      <div className="glass-mystic p-8 rounded-[3rem] border border-white/10 mx-2 flex justify-between items-center shadow-2xl relative overflow-hidden">
