interface DiagnosisProps {
  onComplete: (score: number, name: string) => void;
  userProfile: UserProfile;
}

const Diagnosis: React.FC<DiagnosisProps> = ({ onComplete, userProfile }) => {
  const [selectedPhysical, setSelectedPhysical] = useState<string[]>([]);
  const [selectedSpiritual, setSelectedSpiritual] = useState<string[]>([]);
  const [activeTab, setActiveTab] = useState<'physical' | 'spiritual'>('physical');
  const [step, setStep] = useState<'intro' | 'quiz' | 'result'>('intro');
  const [userName, setUserName] = useState('');

  const handleComplete = () => {
    const score = selectedPhysical.length + selectedSpiritual.length;
    onComplete(score, userName.trim() || 'Buscador');
  };

  const toggleItem = (id: string, list: string[], setList: (l: string[]) => void) => {
    if (list.includes(id)) {
      setList(list.filter(i => i !== id));
    } else {
      setList([...list, id]);
    }
  };

  if (step === 'intro') {
    return (
      <div className="p-8 min-h-screen flex flex-col justify-center items-center text-center animate-in fade-in">
        <div className="glass-mystic p-10 rounded-[3rem] space-y-8 max-w-sm border-magic-gold/20 shadow-[0_0_50px_rgba(212,175,55,0.1)]">
          <div className="w-20 h-20 bg-magic-gold/20 rounded-full flex items-center justify-center mx-auto border border-magic-gold/30">
            <Flame size={36} className="text-magic-gold" />
          </div>
          <div className="space-y-4">
            <h2 className="text-3xl font-serif text-white italic">O Templo e a Luz</h2>
            <p className="text-ethereal-300 text-sm leading-relaxed">
              Mapear onde sua centelha divina encontra resistência no templo físico é o primeiro passo da sua autocura. Vamos ouvir o que sua essência tem a dizer através dos sinais do corpo.
            </p>
          </div>
          <button
            onClick={() => setStep('quiz')}
            className="w-full bg-white text-nature-950 py-5 rounded-3xl font-bold text-lg hover:scale-105 transition-all shadow-xl"
          >
            Escutar a Essência
          </button>
        </div>
      </div>
    );
  }

  if (step === 'quiz') {
    return (
      <div className="p-4 pt-12 pb-32 space-y-8 animate-in fade-in">
        <header className="px-4 text-center space-y-2">
          <h2 className="text-3xl font-serif text-white tracking-tight italic">Inventário de Presença</h2>
          <div className="flex glass-mystic p-1 rounded-2xl gap-1 mt-6">
            <button 
              onClick={() => setActiveTab('physical')}
              className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === 'physical' ? 'bg-magic-gold text-nature-950 shadow-lg' : 'text-ethereal-500'}`}
            >
              Exame do Templo
            </button>
            <button 
              onClick={() => setActiveTab('spiritual')}
              className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === 'spiritual' ? 'bg-magic-gold text-nature-950 shadow-lg' : 'text-ethereal-500'}`}
            >
              Exame do Espírito
            </button>
          </div>
        </header>

        <div className="space-y-4 px-2 animate-in slide-up">
          {activeTab === 'physical' ? (
            <>
              <div className="p-6 bg-rose-950/40 border border-rose-500/40 rounded-[2.5rem] space-y-4 shadow-2xl relative overflow-hidden group">
                <div className="absolute top-0 right-0 w-24 h-24 bg-rose-500/10 blur-2xl pointer-events-none" />
                <div className="flex items-center gap-3 text-rose-300">
                  <ShieldAlert size={22} className="animate-pulse" />
                  <span className="text-[11px] font-black uppercase tracking-[0.2em]">Responsabilidade e Verdade</span>
                </div>
                <div className="space-y-3">
                  <p className="text-[12px] text-ethereal-100 leading-relaxed italic font-medium">
                    Este inventário mapeia sinais que sua centelha divina emite através do corpo. <strong className="text-white">Atenção: Estas informações são informativas e não substituem o diagnóstico clínico de um médico ou nutricionista.</strong>
                  </p>
                  <p className="text-[12px] text-rose-300 leading-relaxed italic border-l-2 border-rose-500/40 pl-3">
                    O desequilíbrio inflamatório (causado por glúten, leite, açúcar, ultraprocessados ou óleos vegetais) obstrui seu canal espiritual. Se identificar múltiplos sinais, honre seu templo buscando confirmação médica formal.
                  </p>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-3">
                {PHYSICAL_SIGNALS.map(item => (
                  <button
                    key={item.id}
                    onClick={() => toggleItem(item.id, selectedPhysical, setSelectedPhysical)}
                    className={`w-full p-5 rounded-[2rem] border transition-all text-left flex justify-between items-center ${
                      selectedPhysical.includes(item.id) ? 'bg-magic-gold/20 border-magic-gold shadow-md' : 'glass-mystic border-white/5'
                    }`}
                  >
                    <span className="text-xs font-medium text-white/90 leading-snug pr-4">{item.name}</span>
                    <div className={`w-6 h-6 rounded-full border flex items-center justify-center shrink-0 ${selectedPhysical.includes(item.id) ? 'bg-magic-gold border-magic-gold shadow-[0_0_10px_rgba(212,175,55,0.5)]' : 'border-white/20'}`}>
