  Sun as SunIcon,
  Compass as CompassIcon,
  FlaskConical as FlaskConicalIcon,
  Footprints as FootprintsIcon
} from 'lucide-react';

interface DashboardProps {
  userProfile: UserProfile;
  logs: DailyLog[];
  onToggleGoal: (goalKey: keyof DailyLog['completedActions']) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ userProfile, logs, onToggleGoal }) => {
  const [insight, setInsight] = useState<string | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const todayLog = logs.find(l => l.date === todayStr);

  const todaysGoals = useMemo(() => {
    return [
      { id: 'alkalinity', label: 'Purificação do Templo', icon: FlaskConicalIcon, desc: 'Shot de despertar ou protocolo de purificação (alho/limão).' },
      { id: 'sunlight', label: 'Banho de Sol (15min)', icon: SunIcon, desc: 'Absorver luz solar direta para nutrir a biologia e o espírito.' },
      { id: 'grounding', label: 'Aterramento Sagrado', icon: FootprintsIcon, desc: 'Pés descalços na terra para descarregar tensões e ancorar luz.' },
      { id: 'silence', label: 'Silêncio Sagrado', icon: MoonIcon, desc: 'Ouvir o silêncio para sintonizar a voz da intuição.' },
      { id: 'meditation', label: 'Conexão com a Fonte', icon: SparklesIcon, desc: 'Portal de Autocura: Alinhamento energético e presença.' },
      { id: 'shadowWork', label: 'Integração da Sombra', icon: CloudLightningIcon, desc: 'Observar gatilhos emocionais e irritabilidade no Templo.' },
      { id: 'presence', label: 'Consciência Corporal', icon: EyeIcon, desc: 'Habitar o corpo com atenção plena em cada movimento.' },
      { id: 'movement', label: 'Movimento Vital', icon: WindIcon, desc: 'Fluidez física para destravar fluxos energéticos.' },
    ];
  }, [todayLog]);

  const completedCount = todaysGoals.filter(g => todayLog?.completedActions[g.id as keyof DailyLog['completedActions']]).length;

  useEffect(() => {
    const fetchInsight = async () => {
      if (logs.length >= 2 && !insight) {
        setLoadingInsight(true);
        const result = await analyzeSoulJourney(logs);
        setInsight(result);
        setLoadingInsight(false);
      }
    };
    fetchInsight();
  }, [logs]);

  return (
    <div className="p-6 pb-32 max-w-2xl mx-auto space-y-12 animate-in fade-in relative overflow-hidden">
      <header className="flex justify-between items-start z-10">
        <div className="space-y-1">
          <p className="text-magic-gold font-black text-[10px] uppercase tracking-[0.4em]">Portal de Ascensão</p>
          <h2 className="text-4xl font-serif text-white leading-tight">Olá, {userProfile.name}</h2>
        </div>
        <div className="glass-mystic text-white px-4 py-2 rounded-2xl flex items-center gap-2 border border-white/10">
          <StarIcon size={14} className="text-magic-gold" />
          <span className="text-[10px] font-bold uppercase tracking-widest">Dia {logs.length + 1} na Senda</span>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 items-stretch">
        <section className="relative flex flex-col items-center justify-center py-10 glass-mystic rounded-[4rem] border border-white/5 bg-nature-950/20 shadow-2xl">
          <div className="relative w-40 h-40 flex items-center justify-center">
            <div className="absolute inset-0 bg-magic-gold/10 blur-[40px] rounded-full animate-pulse" />
            <svg viewBox="0 0 100 100" className="w-full h-full transform -rotate-90">
              <circle cx="50" cy="50" r="45" fill="transparent" stroke="rgba(255,255,255,0.05)" strokeWidth="6" />
              <circle 
                cx="50" cy="50" r="45" 
                fill="transparent" 
                stroke="#d4af37" 
                strokeWidth="6" 
                strokeDasharray="283" 
                strokeDashoffset={283 - (283 * completedCount / todaysGoals.length)}
                strokeLinecap="round"
                className="transition-all duration-[1500ms] ease-in-out"
              />
            </svg>
            <div className="absolute flex flex-col items-center">
              <span className="text-4xl font-serif font-bold text-white">{completedCount}</span>
              <span className="text-[8px] font-black text-magic-gold uppercase tracking-widest">Alquimias</span>
            </div>
          </div>
          <div className="mt-6 text-center">
             <p className="text-[10px] font-black text-ethereal-500 uppercase tracking-[0.3em]">Equilíbrio do Templo</p>
          </div>
        </section>

        {insight && (
          <section className="glass-mystic rounded-[3rem] p-8 flex flex-col justify-center items-center text-center space-y-4 border border-magic-gold/20 bg-magic-gold/5 animate-in slide-up">
            <CompassIcon size={24} className="text-magic-gold animate-spin-slow" />
            <h3 className="text-xs font-black uppercase tracking-widest text-white">Voz do Oráculo</h3>
            <p className="text-sm text-ethereal-100 italic leading-relaxed">"{insight}"</p>
          </section>
        )}
      </div>

      <section className="space-y-6">
        <div className="px-4">
          <h3 className="text-2xl font-serif text-white tracking-tight">Intenções Sagradas</h3>
        </div>

        <div className="grid grid-cols-1 gap-3 px-2">
          {todaysGoals.map((goal) => (
            <button 
              key={goal.id}
              onClick={() => onToggleGoal(goal.id as any)}
              className={`p-6 rounded-[2.5rem] flex items-center gap-5 border transition-all duration-500 text-left group ${
                todayLog?.completedActions[goal.id as keyof DailyLog['completedActions']] 
                  ? 'bg-magic-gold/20 border-magic-gold/40' 
                  : 'glass-mystic border-white/5 hover:border-magic-gold/30'
              }`}
            >
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${
                todayLog?.completedActions[goal.id as keyof DailyLog['completedActions']] ? 'bg-magic-gold text-nature-950 shadow-lg shadow-magic-gold/20' : 'bg-white/5 text-ethereal-500'
              }`}>
                <goal.icon size={24} />
              </div>
              <div className="flex-1">
                <span className="font-bold text-sm text-white block group-hover:text-magic-gold transition-colors">{goal.label}</span>
                <span className="text-[9px] text-ethereal-500 leading-tight block mt-1">{goal.desc}</span>
              </div>
            </button>
          ))}
        </div>
      </section>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import Diagnosis from './components/Diagnosis';
import Dashboard from './components/Dashboard';
import Tracker from './components/Tracker';
import Wellness from './components/Wellness';
import Guidance from './components/Guidance';
import Community from './components/Community';
import WelcomeCover from './components/WelcomeCover';
import InstructionPortal from './components/InstructionPortal';
import { AppView, UserProfile, DailyLog } from './types';
import { Compass, Sparkles, X, Flame } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.WELCOME);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Buscador',
    startDate: null,
    awakeningScore: 0,
    hasSeenWarning: false,
    isOnPath: false,
  });
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [showNavNudge, setShowNavNudge] = useState(false);

  useEffect(() => {
    const savedProfile = localStorage.getItem('userProfile_spiritual');
    const savedLogs = localStorage.getItem('userLogs_spiritual');

    if (savedProfile) {
      const parsedProfile = JSON.parse(savedProfile);
      setUserProfile(parsedProfile);
      if (parsedProfile.isOnPath) {
        setCurrentView(AppView.DASHBOARD);
      }
    }
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem('userProfile_spiritual', JSON.stringify(userProfile));
  }, [userProfile]);

  useEffect(() => {
    localStorage.setItem('userLogs_spiritual', JSON.stringify(logs));
  }, [logs]);

  // Trigger nudge on view change
  useEffect(() => {
    if (userProfile.isOnPath && currentView !== AppView.WELCOME && currentView !== AppView.DIAGNOSIS && currentView !== AppView.INSTRUCTIONS) {
      setShowNavNudge(true);
      const timer = setTimeout(() => {
        setShowNavNudge(false);
      }, 5000);
      return () => clearTimeout(timer);
    }
  }, [currentView, userProfile.isOnPath]);

  const handleDiagnosisComplete = (score: number, name: string) => {
    setUserProfile(prev => ({
      ...prev,
      name: name,
      awakeningScore: score,
      hasSeenWarning: true,
      startDate: new Date().toISOString(),
      isOnPath: true
    }));
    setTimeout(() => setCurrentView(AppView.DASHBOARD), 1000);
  };

  const handleSaveLog = (log: DailyLog) => {
    setLogs(prev => {
      const exists = prev.findIndex(l => l.date === log.date);
      if (exists >= 0) {
        const newLogs = [...prev];
        newLogs[exists] = log;
        return newLogs;
      }
      return [...prev, log];
    });
  };

  const toggleDailyGoal = (goalKey: keyof DailyLog['completedActions']) => {
    const today = new Date().toISOString().split('T')[0];
    setLogs(prev => {
      const existingIndex = prev.findIndex(l => l.date === today);
      const newLogs = [...prev];

      if (existingIndex >= 0) {
        const log = { ...newLogs[existingIndex] };
        log.completedActions = { 
          ...log.completedActions, 
          [goalKey]: !log.completedActions[goalKey] 
        };
        newLogs[existingIndex] = log;
      } else {
        const newLog: DailyLog = {
          date: today,
          spiritualPractices: { morning: '', afternoon: '', evening: '' },
          reflection: '',
          energyLevel: 3,
          awarenessLevel: 3,
          completedActions: {
            silence: false,
            study: false,
            meditation: false,
            shadowWork: false,
            natureConnection: false,
            gratitude: false,
            presence: false,
            movement: false,
            alkalinity: false,
            sunlight: false,
            grounding: false,
            [goalKey]: true
          }
        };
        newLogs.push(newLog);
      }
      return newLogs;
    });
  };

  const renderView = () => {
    switch (currentView) {
      case AppView.WELCOME:
        return <WelcomeCover onStart={() => setCurrentView(AppView.INSTRUCTIONS)} />;
      case AppView.INSTRUCTIONS:
        return <InstructionPortal onProceed={() => setCurrentView(userProfile.isOnPath ? AppView.DASHBOARD : AppView.DIAGNOSIS)} />;
      case AppView.DIAGNOSIS:
        return <Diagnosis onComplete={handleDiagnosisComplete} userProfile={userProfile} />;
      case AppView.DASHBOARD:
        return <Dashboard userProfile={userProfile} logs={logs} onToggleGoal={toggleDailyGoal} />;
      case AppView.TRACKER:
        return <Tracker onSaveLog={handleSaveLog} logs={logs} />;
      case AppView.WELLNESS:
        return <Wellness />;
      case AppView.GUIDANCE:
        return <Guidance />;
      case AppView.COMMUNITY:
        return <Community />;
      default:
        return <Dashboard userProfile={userProfile} logs={logs} onToggleGoal={toggleDailyGoal} />;
    }
  };

  return (
    <div className="min-h-screen bg-ethereal-950 text-gray-100 font-sans selection:bg-magic-gold/30">
      <main className="mx-auto max-w-md bg-transparent min-h-screen shadow-2xl relative overflow-x-hidden">

        <div className="relative z-10 pt-8">{renderView()}</div>

        {/* Nudge Toast for Navigation */}
        {showNavNudge && currentView !== AppView.INSTRUCTIONS && (
          <div className="fixed bottom-28 left-1/2 -translate-x-1/2 z-50 w-[85%] max-w-sm animate-in slide-up">
            <div className="glass-mystic p-4 rounded-2xl border border-magic-gold/20 flex items-center gap-4 shadow-[0_10px_30px_rgba(0,0,0,0.5)] bg-ethereal-950/80 backdrop-blur-xl">
               <div className="shrink-0 p-2 bg-magic-gold/10 rounded-lg text-magic-gold">
                  <Compass size={18} className="animate-spin-slow" />
               </div>
               <div className="flex-1">
                  <p className="text-[10px] font-black uppercase tracking-widest text-magic-gold">Voz da Centelha</p>
                  <p className="text-[11px] text-ethereal-100 italic leading-relaxed">Honre seu tempo peregrinando por todos os portais da senda.</p>
               </div>
               <button onClick={() => setShowNavNudge(false)} className="text-ethereal-500 hover:text-white transition-colors">
                  <X size={14} />
               </button>
            </div>
          </div>
        )}

        <div className="fixed top-[-10%] left-[-10%] w-full h-full bg-magic-gold/5 blur-[150px] pointer-events-none rounded-full" />
        <div className="fixed bottom-[-10%] right-[-10%] w-full h-full bg-ethereal-500/5 blur-[150px] pointer-events-none rounded-full" />
      </main>

      {userProfile.isOnPath && currentView !== AppView.WELCOME && currentView !== AppView.INSTRUCTIONS && (
        <Navigation currentView={currentView} setView={setCurrentView} />
      )}
    </div>
  );
};

