      { id: 'grounding', label: 'Aterramento Sagrado', icon: FootprintsIcon, desc: 'Pés descalços na terra para descarregar tensões e ancorar luz.' },
      { id: 'silence', label: 'Silêncio Sagrado', icon: MoonIcon, desc: 'Ouvir o silêncio para sintonizar a voz da intuição.' },
      { id: 'meditation', label: 'Conexão com a Fonte', icon: SparklesIcon, desc: 'Portal de Autocura: Alinhamento energético e presença.' },
      { id: 'shadowWork', label: 'Integração da Sombra', icon: CloudLightningIcon, desc: 'Observar gatilhos emocionais e irritabilidade no Templo.' },
