const Wellness: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [ritualStep, setRitualStep] = useState<'idle' | 'preparing' | 'breathing' | 'feeling' | 'affirming' | 'checking' | 'completed'>('idle');
  const [activePortal, setActivePortal] = useState<typeof HEALING_PORTALS[0] | null>(null);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);

  const initAudioContext = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
  };

  const playAudio = async (base64: string) => {
    initAudioContext();
    const ctx = audioContextRef.current!;
    if (ctx.state === 'suspended') await ctx.resume();

    const bytes = decodeBase64(base64);
    const audioBuffer = await decodeAudioData(bytes, ctx, 24000, 1);

    return new Promise<void>((resolve) => {
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => {
        setIsPlayingAudio(false);
        resolve();
      };
      setIsPlayingAudio(true);
      source.start();
    });
  };

  const startRitual = async (portalId: string) => {
    const portal = HEALING_PORTALS.find(p => p.id === portalId);
    if (!portal) return;

    setLoading(true);
    setActivePortal(portal);
    setRitualStep('preparing');

    try {
      const steps = ['breathing', 'feeling', 'affirming', 'checking'] as const;

      for (const step of steps) {
        setRitualStep(step);
        const textToSpeak = portal.steps[step];
        const audioBase64 = await generateSpeech(textToSpeak);

        if (audioBase64) {
          await playAudio(audioBase64);
        } else {
          // Fallback if TTS fails
          await new Promise(r => setTimeout(r, 6000));
        }
      }
      setRitualStep('completed');
    } catch (e) {
      console.error("Audio ritual failed:", e);
      setRitualStep('idle');
